import{D as t,S as e,M as l}from"./index-D8x7OQIy.js";const a=[{id:"v-fill-001",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"37.今天，关于传统文化的书写，存在两个极端：要么过于通俗，要么过于玄虚。中国传统文化的传播、国学的弘扬，需要摆脱掉这两个极端，走一条中间道路，做到______、微言大义。虽然，“文化热”“儒学热”“国学热”的浪潮______，但真正将自己的文化看作安身立命之本的人却是______。很多人对待文化，对待国学，仍然没有走出经世致用、急功近利的目的预设。",options:[{label:"A",text:"深入浅出 此起彼伏 少之又少"},{label:"B",text:"大道至简 前仆后继 凤毛麟角"},{label:"C",text:"通俗易懂 如火如荼 寥寥无几"},{label:"D",text:"不温不火 不绝如缕 后继无人"}],answer:"C",explanation:"",tags:["逻辑填空","2019联考A"],year:2019},{id:"v-fill-002",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"40.年轻干部要想行得端、走得正，就必须涵养道德操守，明礼诚信，特别是要敢于讲真话、讲实话，切忌开“空头支票”，______说好话、______说套话、______说大话、规避责任说假话。",options:[{label:"A",text:"曲意逢迎 心口不一 不切实际"},{label:"B",text:"委曲求全 虚与委蛇 好高骛远"},{label:"C",text:"阿谀奉承 独善其身 好大喜功"},{label:"D",text:"投其所好 明哲保身 沽名钓誉"}],answer:"B",explanation:"",tags:["逻辑填空","2019联考A"],year:2019},{id:"v-fill-003",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"59.________________________。我国正处于全面建成小康社会的决胜阶段，人口老龄化、资源环境约束等挑战依然严峻，人工智能在教育、医疗、养老、环境保护、城市运行、司法服务等领域广泛应用，将极大提高公共服务精准化水平，全面提升人民生活品质。人工智能技术可准确感知、预测、预警基础设施和社会安全运行的重大态势，及时把握群体认知及心理变化，主动决策反应，将显著提高社会治理的能力和水平，对有效维护社会稳定具有不可替代的作用。",options:[{label:"A",text:"人工智能带来社会建设的新机遇"},{label:"B",text:"人工智能促进公共服务管理水平提升"},{label:"C",text:"人工智能助力社会自动化、服务精准化"},{label:"D",text:"人工智能在教育、医疗、预警等领域应用拓展"}],answer:"A",explanation:"",tags:["逻辑填空","2019联考A"],year:2019},{id:"v-fill-004",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"60.从抑郁到认知能力下降，到心脏问题和中风，越来越多的证据将孤独与心理、生理疾病联系在了一起。在某些时刻，我们都会感到“孤独”。但对于我们中的大多数人来说，孤独的感觉取决于我们的状态以及如何看待它。孤独被定义为可以感知的社交隔离和与他人切断联系的经历。大多数经历孤独的人，____________________，比如找到新朋友或开始一段新恋情。研究人员也提到过一些“长期孤独”人群，他们在一生中经历了沉重的孤独，即便所处的环境或人际关系发生变化也无法改变他们孤独的感觉。",options:[{label:"A",text:"只要改变心态，就能改变感到孤独状态"},{label:"B",text:"只有改变心态，才能改变感到孤独状态"},{label:"C",text:"通过改变心态，可以改变感到孤独状态"},{label:"D",text:"只需改变心态，就能改变感到孤独状态"}],answer:"D",explanation:"",tags:["逻辑填空","2019联考A"],year:2019},{id:"v-fill-005",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"55.敦煌研究院将与外部机构进一步合作，开展敦煌壁画的保护和修复，为这个文化宝藏的永续保存探讨更多可能性。保护和修复也为了更好地传播，依托数字化，“数字敦煌”资源库在2016年上线。资源库第一期的30个经典石窟，跨越北魏、西魏、北周、隋、唐等多个时期，其中绝大多数石窟都是未对游客开放的，全球网友只需轻点鼠标，就可以免费360度漫游洞窟，足不出户便能近距离感受千年的文化。千年敦煌石窟，正借助科技的手段，_________________，焕发出新的生命与活力。",options:[{label:"A",text:"力求重建用户沉浸式体验"},{label:"B",text:"以虚拟世界代替现实场景"},{label:"C",text:"突破时间、空间上的限制"},{label:"D",text:"促进与传统文化深度融合"}],answer:"D",explanation:"",tags:["逻辑填空","2019联考B"],year:2019},{id:"v-fill-006",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"57.为了帮助贫困地区脱贫，长期以来，社会各界以多种形式开展帮扶，扶贫思路更加清晰，扶贫手段更加多样，文化扶贫、旅游扶贫、电商扶贫等新方式效果显著，脱贫攻坚实现换挡提速。但一些尚未脱贫的地区，因为自然条件恶劣，发展脱贫产业难度较大。要啃下扶贫的“硬骨头”，还需打好科技牌。最适合做这段文字标题的是（）。",options:[{label:"A",text:"打好脱贫攻坚科技牌"},{label:"B",text:"啃下扶贫的“硬骨头”"},{label:"C",text:"选好脱贫攻坚新方式"},{label:"D",text:"脱贫攻坚实现换挡提速"}],answer:"B",explanation:"",tags:["逻辑填空","2019联考B"],year:2019},{id:"v-fill-007",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"58.工匠精神，匠心为本。有没有工匠精神，关键是看有没有一颗安于默默无闻、执着于追求卓越的匠心。树匠心，就要坚守初心、执着专注，秉持赤子之心，摒弃浮躁喧嚣，在本职岗位上坐得住、做得好。怎样才能坐得住、做得好?关键是要做到专心专注、追求至精至善，将产品的每个细节都尽可能做到极致。这段文字意在强调（）。",options:[{label:"A",text:"育匠人是传承工匠精神的基础"},{label:"B",text:"树匠心是弘扬工匠精神的根本"},{label:"C",text:"树匠心要坚守初心、执着专注"},{label:"D",text:"树匠心需要良好的社会文化环境"}],answer:"D",explanation:"",tags:["逻辑填空","2019联考B"],year:2019},{id:"v-fill-008",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"59.在今天的社会文化实践中，我们更要关注当下的传统文化热是否真正触及了传统文化的人文精神实质，是否真正提升了人们的精神境界。一般而言，文化的形式要自觉为文化的内容服务，如果忽略了文化的内容，尤其是忽略了对贯穿其中的人文精神的追求，就必然会走入歧途，背离我们弘扬传统文化的初衷。文化是活的，不能做简单的固化处理，更不能只注重形式而忽略对其内涵的传承。鉴于此，我们必须_________________。",options:[{label:"A",text:"改变过于强调传统文化的符号性的做法"},{label:"B",text:"注意纠正传统文化弘扬中的形式化倾向"},{label:"C",text:"以实用心态凸显传统文化的工具性价值"},{label:"D",text:"借助现代电子技术手段来弘扬传统文化"}],answer:"A",explanation:"",tags:["逻辑填空","2019联考B"],year:2019},{id:"v-fill-009",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"12.民族精神是衡量一个国家综合国力强弱至关重要的因素之一，是衡量一个民族有无凝聚力、向心力、战斗力的重要指标之一。一个国家重视民族精神的培养，就能凝心聚力、______，各项事业就会______；忽视民族精神的培养，只会______、消极颓废，各项事业都难以搞好。",options:[{label:"A",text:"奋发图强 一日千里 一盘散沙"},{label:"B",text:"精神振奋 兴旺发达 人心涣散"},{label:"C",text:"聚精会神 繁荣昌盛 离心离德"},{label:"D",text:"精神抖擞 蒸蒸日上 分崩离析"}],answer:"B",explanation:"",tags:["逻辑填空","2020联考A"],year:2020},{id:"v-fill-010",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"17.病毒的故事或许还要从远古说起。在那个______的地球上，海洋占据了世界的绝大部份，而无垠的大海之下是数亿年______的火山活动。在某些______之下，海水中产生了史上第一批有机大分子，从而点燃了生命的星星之火。",options:[{label:"A",text:"病入膏肓 动荡不安 阴差阳错"},{label:"B",text:"死气沉沉 经天纬地 不期而遇"},{label:"C",text:"了无生机 连绵不断 机缘巧合"},{label:"D",text:"奄奄一息 接踵而至 逢机遘会"}],answer:"A",explanation:"",tags:["逻辑填空","2020联考A"],year:2020},{id:"v-fill-011",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"18.无论经历多少艰难、付出多大牺牲，都不能忘了为什么出发，不能忘了肩负的使命任务，始终信念如磐、意志如铁、______，做到“千磨万击还坚劲，任尔东西南北风”。在见世面中强大内心，既能容得下征途顺利时的春风得意，谦虚谨慎、再接再厉、再创佳绩，也能容得下前进受挫时的______，淡定从容、______、不言放弃，做到“不管风吹浪打，胜似闲庭信步”。",options:[{label:"A",text:"不忘初心 苦心孤诣 积极进取"},{label:"B",text:"初心不改 沉重打击 乐观向上"},{label:"C",text:"牢记使命 困难挫折 开朗乐观"},{label:"D",text:"使命担当 艰苦磨难 力争上游"}],answer:"A",explanation:"",tags:["逻辑填空","2020联考A"],year:2020},{id:"v-fill-012",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"26.智慧城市在带动城市产业发展、转变城市发展模式、推动城市精细化治理等方面具有优势，而且能够在人口、空间、人工智能等方面发挥组合效应，带动政府各部门、城市居民、社会力量共同参与，________________。例如:深圳市确定了智能交通总体框架，既为治堵工作提供了精准的支撑，又通过互联网民意平台推动了交通治理的共享共治。",options:[{label:"A",text:"有助于打造共建共治共享的社会治理格局"},{label:"B",text:"有助于撬动社会治理智能化和法治化支点"},{label:"C",text:"形成信息早掌握、问题早解决的良好局面"},{label:"D",text:"有助于加强信息基础设施的网络安全防护"}],answer:"A",explanation:"",tags:["逻辑填空","2020联考A"],year:2020},{id:"v-fill-013",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"27.近年来随着新品种与种薯引进和全球气候变暖，云南马铃薯病毒优势种发生了变化，科学家在种薯上检测到一种新发病毒病——番茄斑萎病毒属病毒引起的病害，该属病毒除通过带毒种苗、种薯传播外，主要通过蓟马进行传播。因此，明确目前云南马铃薯病毒优势种及其主要媒介蓟马优势种，____________________，并对云南马铃薯斑萎病流行传播及发生风险进行分析，对马铃薯安全生产具有重要意义。",options:[{label:"A",text:"寻求对新发病毒病抑制的具体措施"},{label:"B",text:"重塑云南马铃薯病毒优势种的类型"},{label:"C",text:"掌握蓟马种群结构及区域分布情况"},{label:"D",text:"厘清蓟马作为传播中介的运作机制"}],answer:"A",explanation:"",tags:["逻辑填空","2020联考A"],year:2020},{id:"v-fill-014",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"28.数字经济的重要意义不仅体现在对总量的贡献上，更重要的是________________，一方面表现为数字技术赋能传统产业，另一方面表现为数字技术催生新兴产业。数字技术赋能传统产业，通常也被称为产业数字化，即利用数字技术对传统行业的业务进行升级，进而提升生产数量和效率。从生产流程角度看，数字技术可以通过对企业生产过程中产生的数据进行分析，将程序性业务交给计算机处理，从而降低了操作失误率。同时，企业通过数据分析，能够对业务流程进行全面而系统的监督，及时发现经营过程中的异常和隐患，大大降低风险。",options:[{label:"A",text:"及时降低企业经营过程中的损耗与风险"},{label:"B",text:"将数字化的知识和信息转化为生产要素"},{label:"C",text:"对产业结构优化升级所起到的推动作用"},{label:"D",text:"不断发掘与推动产业经济的新增长点"}],answer:"D",explanation:"",tags:["逻辑填空","2020联考A"],year:2020},{id:"v-fill-015",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"14.我国研究机构日前宣布，世界上第一个全超导托卡马克“东方超环”（EAST）实现了稳定的101.2秒稳态长脉冲高约束等离子体运行，创造了新的世界记录。这标志着EAST成为世界上第一个实现稳态高约束模式运行持续时间达到百秒量级的托卡马克核聚变实验装置。EAST高11米、直径8米、重达400吨，是我国第四代核聚变实验装置，其科学目标是让海水中大量存在的氘和氚在高温条件下，像太阳一样发生核聚变，为人类提供源源不断的清洁能源，所以也被称为“人造太阳”。这段文字主要说明了（）。",options:[{label:"A",text:"大力发展清洁能源势在必行"},{label:"B",text:"核聚变技术可创造清洁能源"},{label:"C",text:"短期内难建成真正的“人造太阳”"},{label:"D",text:"“人造太阳”装置取得革命性突破"}],answer:"C",explanation:"",tags:["逻辑填空","2020联考B"],year:2020},{id:"v-fill-016",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"15.网络书店的页面为了适应人眼的视野范围，又窄又长，容易让人疲倦，而且图书多按销量或排行榜来呈现。随着人工智能的发展，现在还可以利用大数据算法，根据读者浏览和购买历史来确定其读书品味，推荐的书目符合读者口味，这就不可避免地形成“蚕茧效应”，读者只能看到喜欢看的，长此以往，_______________，这样的不足正好可以通过实体书店来弥补。现在不少大型书店的在售图书多到十万种以上，一入书城，如进书海，给读者带来的体验是网络书店无法比拟的。此时，书店如果能从众多图书中挑选高品质图书，用品质赢得读者，就可以在和网店的竞争中凸显竞争力。",options:[{label:"A",text:"读者在网络书店的收获越来越小"},{label:"B",text:"逛实体书店才可能带来意外惊喜"},{label:"C",text:"读者阅读视野不知不觉日益狭窄"},{label:"D",text:"网络书店无法满足读者阅读需求"}],answer:"A",explanation:"",tags:["逻辑填空","2020联考B"],year:2020},{id:"v-fill-017",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"20.正因为中国法律史学除了单纯的理论研究，还要探究解决当代中国的法律问题，所以有必要坚持独立的中国立场。不论是单纯的理论研究，还是切近实际的应用研究，都需坚持独立思想立场才能做出有价值的研究成果。这里的独立立场，其实就是中国自身的立场，而不是站在别国的立场之上。近代以来，西方国家一些学者对于中国法律不客观的负面评价，曾经影响到中国学者对待本国法律历史的态度。直到今天，这种影响仍没有完全消除，需要加以矫正。这段文字旨在强调（）。",options:[{label:"A",text:"中国法律史学研究需探究解决当代中国的法律问题"},{label:"B",text:"中国法律史学研究受到西方学者不客观的负面评价"},{label:"C",text:"中国法律史学研究必须坚持中国自身独立的立场"},{label:"D",text:"中国法律史学研究曾受西方学者影响至今未消除"}],answer:"B",explanation:"",tags:["逻辑填空","2020联考B"],year:2020},{id:"v-fill-018",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"21.曹雪芹通过贾府的衣食住行把______人家的富贵之相刻画得淋漓尽致。一屋一室，或雕梁画栋，或______，或金碧辉煌，或简约古朴，相映成辉，相映成画；一餐一饮精烹细作，食不厌精；______，雀衣彩绣，美轮美奂。但仍然没有宴席上的浅斟深酌更能体现出贾府“鲜花着锦、烈火烹油”之盛；没有比推杯换盏之时的琴歌酒赋更能体现出翰墨书香之族的风流雅致。",options:[{label:"A",text:"筚门圭窦 岸芷汀兰 一裙一裳"},{label:"B",text:"兰艾同焚 粉墙黛瓦 一丝一缕"},{label:"C",text:"钟鸣鼎食 曲径通幽 一衣一带"},{label:"D",text:"桑枢瓮牖 小桥流水 一鞋一袜"}],answer:"C",explanation:"",tags:["逻辑填空","2020联考B"],year:2020},{id:"v-fill-019",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"22.近年来，人们的生活条件越来越好，对旅游______的要求也越来越高，从前到此一游、______的旅游方式已逐渐被深度体验、注重文化与互动的旅游方式所替代。正是在这种背景下，文化与旅游融合的发展方式______，并成为热点。",options:[{label:"A",text:"质量 浮光掠影 脱颖而出"},{label:"B",text:"环境 浅尝辄止 蔚然成风"},{label:"C",text:"品质 走马观花 应运而生"},{label:"D",text:"生态 蜻蜓点水 蔚为大观"}],answer:"B",explanation:"",tags:["逻辑填空","2020联考B"],year:2020},{id:"v-fill-020",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"40.面对民族存亡的空前危机，中国人民的爱国热情像火山一样迸发出来。全体中华儿女______、共御外侮，为民族而战，为祖国而战，为尊严而战，汇聚起气势磅礴的力量。在这一壮阔进程中，中国人民向世界展示了视死如归、______的民族气节，百折不挠、______的必胜信念，铸就了伟大的抗战精神。",options:[{label:"A",text:"团结一心 见义勇为 勇往直前"},{label:"B",text:"众志成城 宁死不屈 坚韧不拔"},{label:"C",text:"风雨同舟 英勇无畏 能屈能伸"},{label:"D",text:"同舟共济 宁折不弯 意志坚定"}],answer:"B",explanation:"",tags:["逻辑填空","2021联考A"],year:2021},{id:"v-fill-021",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"48.荷兰研究人员意外地在人体中发现了一个新器官——一组位于鼻子后面、喉咙上部深处的唾液腺。这组平均长度大约4厘米的唾液腺位于一块被称为咽鼓管隆凸的软骨之上，研究人员将其称为“咽鼓管唾液腺”，它们很可能是人体用来湿润上咽喉部的。此前已知人体中有三大唾液腺，即腮腺、颌下腺和舌下腺。而这个不起眼的咽鼓管唾液腺，可能会影响癌症治疗。在头颈部位使用放射性疗法治疗癌症时，医生应该设法避免照射这一唾液腺，因为破坏这些腺体，可能会影响患者的进食、吞咽甚至说话功能。最适合做这段文字标题的是（）。",options:[{label:"A",text:"人体唾液腺知多少"},{label:"B",text:"治疗癌症的新方法"},{label:"C",text:"人体隐秘器官新发现"},{label:"D",text:"放射性治疗中的禁区"}],answer:"C",explanation:"",tags:["逻辑填空","2021联考A"],year:2021},{id:"v-fill-022",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"49.互联网的发展，为文学的创作和传播提供了开放的平台，让更多人加入了创作的行列。但凡事都有两面性，_______________。一方面，网络文学“洗稿”简单、“融梗”容易、“复制粘贴”难度小，与传统的“抄袭”相比，界定困难；另一方面，尽管我国在知识产权保护上不断加码，但网络文学的新形式、新变化，还是给网络抄袭的治理带来了新的挑战。在此背景下，原作者想要维权成功，无疑难度更大；而且即便维权成功，也存在难以执行的情况。",options:[{label:"A",text:"原本就苦抄袭久矣的影视圈更加乱象丛生"},{label:"B",text:"随之而来的是原创知识产权维护难上加难"},{label:"C",text:"影视作品抄袭的收益与风险越发不成比例"},{label:"D",text:"走红影视剧引发的抄袭之争应当引起重视"}],answer:"C",explanation:"",tags:["逻辑填空","2021联考A"],year:2021},{id:"v-fill-023",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"57.当前，我国对互联网平台经济创新秉持“包容审慎”的监管原则，然而这并不意味着监管部门可以放任不管。“包容”意在鼓励创新，为各类企业特别是初创型中小企业在发展早期提供更加宽容的营商环境和法治环境，是尊重市场新业态发展规律的体现；“审慎”则是在法治框架和法治原则下开展监管，在触及法治底线和监管红线的问题上必须严格依法监管。因此，______________，应合理界定有效创新与有为监管的边界，在鼓励创新与防范风险之间寻求法治框架下的动态平衡。",options:[{label:"A",text:"保障平台经济在创新发展与监管内运行"},{label:"B",text:"面对平台经济创新发展中的风险和挑战"},{label:"C",text:"平台风险控制和危机管理容易陷入困境"},{label:"D",text:"正确甄别平台的经济创新和发展的能力"}],answer:"B",explanation:"",tags:["逻辑填空","2021联考A"],year:2021},{id:"v-fill-024",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"59.随着互联网的普及，会有越来越多的老年人掌握互联网技术，能够熟练使用智能手机。但要知道，技术的发展是在不断演进的，一个社会总会不断出现新的“落伍者”，即便是今天在数字化社会中成长起来的年轻人，未来也可能沦为“落伍者”，面临今天部分老人所面临的困境。因此，抛开技术不谈，我们的公共服务，首先还是应在理念上有更多的包容、普惠底色，真正依据不同群体的需求去设定公共服务提供方式，而不是一味追求技术上的“现代化”。这段文字意在强调（）。",options:[{label:"A",text:"从资源和技术上能有效解决老年人面临的根本性难题"},{label:"B",text:"老年人在网络时代遭遇数字鸿沟的现象变得更加突出"},{label:"C",text:"在相关领域针对老年人等群体提供更为人性化的服务"},{label:"D",text:"数字化带来便利的同时也给部分老年人群体带来不便"}],answer:"A",explanation:"",tags:["逻辑填空","2021联考A"],year:2021},{id:"v-fill-025",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"60.农民卖粮舒心，源于市场之“手”用得好。2020年的夏粮生产，不仅数量增加，质量也在提升。一个重要指标就是专用麦比例高，全国优质强筋弱筋小麦面积占比35.8%，比上年提高2.8个百分点。从目前收购市场情况看，每斤优质小麦要比普通品种高出0.1元左右。这背后，______________。如今，多元化市场主体入市收购，既让丰收粮有了更加多样化的销售渠道，也让优质粮食品种销路更好、价格更高，优粮优价成为种粮农民增收的“金钥匙”。",options:[{label:"A",text:"说到底就是稳住这些农民的种粮收益，保护农民的种粮积极性"},{label:"B",text:"正是粮食收储制度改革持续推进，市场机制作用得到更好发挥"},{label:"C",text:"全国农户构成了粮食安全的坚强基石，稳住粮食生产的好形势"},{label:"D",text:"通过优化供给体系，拓展粮食产加销增值空间，分享增值收益"}],answer:"D",explanation:"",tags:["逻辑填空","2021联考A"],year:2021},{id:"v-fill-026",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"32.解释国家兴衰是许多学科______的学术好奇心所在，经济学家更是______地发展出各种理论框架，期冀破解经济增长之谜。激励学者们把中国这个经历了由盛至衰的历史作为主要研究对象的，是以著名的中国科技史学家李约瑟命名的所谓“李约瑟之谜”。这个谜题尝试回答为什么在前现代社会，中国科技______于其他文明，而近现代中国不再具有这样的领先地位。",options:[{label:"A",text:"绵延不绝 孜孜矻矻 迥然不同"},{label:"B",text:"旷日持久 孜孜不倦 遥遥领先"},{label:"C",text:"亘古不变 皓首穷经 名列前茅"},{label:"D",text:"持之以恒 殚精竭虑 一枝独秀"}],answer:"B",explanation:"",tags:["逻辑填空","2021联考B"],year:2021},{id:"v-fill-027",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"55.孔子以“有教无类”“因材施教”“教学相长”为方针，以培养“博学通才之士”为目标，对学生进行礼、乐、御、射、书、数“六艺”教育，其中，数即数学，乐和声学有关，御和力学有关，射和机械有关。《中庸》上说，“博学之，审问之，慎思之，明辨之，笃行之”，学、问、思、辨、行，完全符合认识过程和研究科学的方法，即获取信息、提出问题、思维推理、检验结果、躬身实践。在儒家崇尚务实和“经世致用”思想影响下，中国古代科技具有强烈的实用性，形成了以农、医、天、算四大学科和以“四大发明”为代表的技术发明创造。这段文字意在说明（）。",options:[{label:"A",text:"中华古代文明具有文理交融的包容性"},{label:"B",text:"古代科技是传统儒家思想的实现途径"},{label:"C",text:"传统文化和古代科技存在必然的联系"},{label:"D",text:"传统文化对古代科技发展有积极影响"}],answer:"D",explanation:"",tags:["逻辑填空","2021联考B"],year:2021},{id:"v-fill-028",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"56.提到一座城市，人们往往会想到具有代表性的文化地标：600岁的紫禁城见证着北京城的过往，拓荒牛雕塑标记着深圳的开拓进取……城市文化地标________，成为一个城市的精神和文化象征，与人们产生紧密的情感连接、文化认同。文化地标是一个地方的文化名片，在传播城市形象方面有巨大的流量效应。近年来，文化旅游市场持续升温，各类文化地标成为热门参观地、网红打卡地。",options:[{label:"A",text:"大都强调人文景观与自然环境和谐共生，以形神兼备的呈现方式"},{label:"B",text:"或深植于历史文化，或投射着时代风貌，以鲜明独特的符号形象"},{label:"C",text:"不是凭借炫目奇特的视觉效果，或各类时髦文化元素的简单堆砌"},{label:"D",text:"承载着无法替代的人文价值，满足着公众的审美旨趣和美好期待"}],answer:"D",explanation:"",tags:["逻辑填空","2021联考B"],year:2021},{id:"v-fill-029",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"57.从时间的精密测量与相对论的密切关系，我们可以感受到万物相通的奥妙。根据广义相对论，地面（或任何星球）上的两点之间，如果高度不同，时间流逝速度就会有所不同，高处略快。地面上每米的高度差，时间流逝差异大约为10-16。这意味着，_____________，就能推测两点的高度差。这进一步表明，原子钟在测地学、水文学里都会有巨大的应用潜力。",options:[{label:"A",text:"只要用原子钟精确测量两点的时间流逝的差异"},{label:"B",text:"只要明确时间的精密测量与相对论的密切关系"},{label:"C",text:"只要能掌握原子钟碰撞频移的规律和基本参数"},{label:"D",text:"只要能够运用自然界万物相通的法则举一反三"}],answer:"B",explanation:"",tags:["逻辑填空","2021联考B"],year:2021},{id:"v-fill-030",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"60.有人是“早起鸟”，有人是“夜猫子”，每个人都有自己一套独特的生物钟。生物钟是体内控制日常生物节律的系统，帮助调整人体40%左右的基因活动，睡眠、进食、体温、血压等的“节奏编排”均与之相关。测量人体生物钟的常用方法是监测人体内褪黑素浓度的变化，不过此法要求研究对象长时间坐在暗室，每隔大约一小时采集一次血液或唾液的样本。目前，多国科研人员正尝试开发快速检测人体生物钟的新法，以期更好地了解人体，保障健康。研究人员表示，生物钟紊乱与糖尿病、心脏病、抑郁症等多种疾病相关，如能找到检测人体生物钟的简便方法，将有助于人们更好地了解并治疗这些疾病。上述文字重在强调（）。若二维码无法识别，给公众号回复“2026国考合集”或“2026省考合集”即可。2022联考A言语理解与表达（福建、广西、贵州、海南、河南、湖南、云南）",options:[{label:"A",text:"每个人都有一套属于自己的生物钟"},{label:"B",text:"研究生物钟可助于人们更好了解疾病"},{label:"C",text:"科研人员正探索人体生物钟检测新法"},{label:"D",text:"生物钟系统有助于调整人体基因活动"}],answer:"D",explanation:"",tags:["逻辑填空","2021联考B"],year:2021},{id:"v-fill-031",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"24.过去一百年，党向人民、向历史交出了一份优异的答卷。现在，党团结带领中国人民又踏上了实现第二个百年奋斗目标新的赶考之路。让我们更加紧密地团结在以习近平同志为核心的党中央周围，全面贯彻习近平新时代中国特色社会主义思想，坚定理想信念，牢记初心使命，戮力同心、攻坚克难、勇毅前行，以______的执着奋力实现既定目标，以______的清醒不懈推进中华民族伟大复兴！",options:[{label:"A",text:"任尔东西南北风 长风破浪会有时"},{label:"B",text:"不破楼兰终不还 风物长宜放眼量"},{label:"C",text:"粉身碎骨浑不怕 万里长征第一步"},{label:"D",text:"咬定青山不放松 行百里者半九十"}],answer:"D",explanation:"",tags:["逻辑填空","2022联考A"],year:2022},{id:"v-fill-032",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"40.数据安全是全球性问题，没有哪个国家可以______。放眼当今世界，信息化、数字化、网络化、智能化已是______，但规则______是当前全球数字治理领域面临的突出挑战，应对数据安全风险，需要凝聚全球数字治理合力。",options:[{label:"A",text:"明哲保身 势不可挡 空缺"},{label:"B",text:"袖手旁观 蓬勃发展 滞后"},{label:"C",text:"置身事外 方兴未艾 漏洞"},{label:"D",text:"独善其身 大势所趋 缺失"}],answer:"B",explanation:"",tags:["逻辑填空","2022联考A"],year:2022},{id:"v-fill-033",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"46.除了探矿队员，很多矿石收藏家也对铀矿石感兴趣，因为它们实在太漂亮了。然而学过物理、化学的人都知道，不管化学上结合成什么物质，铀元素的放射性都是不会变的。那么把含铀的“毒花”放在博物馆甚至家里，真的没事吗？实际上，只要隔着一层玻璃，这些铀矿石就算放在卧室里都伤不了人。因为它们所含的铀，几乎全是放射性较弱的铀-238（俗称“贫铀”），只有极少量是用于制造核弹头的同位素铀-235。不过千万不要吸入它的粉尘，因为哪怕它所放出的最弱的α射线，也会造成辐射伤害。这段文字意在说明（）。",options:[{label:"A",text:"铀矿石为什么应该保存在玻璃柜中"},{label:"B",text:"铀矿石作为矿石收藏是比较安全的"},{label:"C",text:"铀-238 与同位素铀-235 有本质不同"},{label:"D",text:"粉尘态铀矿石的放射性会大大增强"}],answer:"B",explanation:"",tags:["逻辑填空","2022联考A"],year:2022},{id:"v-fill-034",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"47.哺乳动物繁荣多样，蝙蝠又是哺乳动物中颇为独特的一支。它们是唯一能自主飞行的哺乳动物，还具有惊人的物种多样性：蝙蝠至少有1440个物种，每5个哺乳动物物种中就有一个是蝙蝠。蝙蝠另一重要生物演化特征是它们的回声定位系统。__________，必须有特化的发声结构和高灵敏听觉感观的功能，使其在黑暗中也能“听”清楚周围的环境，寻找食物或躲避障碍。我们常常将蝙蝠与回声定位划上等号，但事实上，并非所有蝙蝠物种都具备这一能力；蝙蝠动物回声定位的功能，在物种间也有差异。蝙蝠回声定位特征的出现，比先前认为的更复杂。",options:[{label:"A",text:"蝙蝠是演化过程中的巨大成功"},{label:"B",text:"回声定位是非常特殊的行为功能"},{label:"C",text:"漫长的演化赋予蝙蝠回声定位系统"},{label:"D",text:"蝙蝠的内耳有密集多交的神经纤维束"}],answer:"A",explanation:"",tags:["逻辑填空","2022联考A"],year:2022},{id:"v-fill-035",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"49.综合危险策略可以很容易把人群预防效果提高5倍、10倍甚至更多，大大优化成本效果。冠心病和中风的危险因素有很多，简单地以一两个危险因素的高低决定如何治疗，不是最精准的策略。恶性高血压一定需要药物控制。对于大部分高血压病人来说，____________，需要治疗的迫切性就越高，降压药、叶酸、阿司匹林治疗的好处就越大，效益就越高，治疗就越精准。",options:[{label:"A",text:"一个人的血压越高，罹患心血管疾病可能性越大"},{label:"B",text:"越不健康的饮食和生活方式越易引发高血压疾病"},{label:"C",text:"高血压患病时间越长，未来中风的风险性就越高"},{label:"D",text:"具有的心血管危险因素越多，未来发病风险越高"}],answer:"C",explanation:"",tags:["逻辑填空","2022联考A"],year:2022},{id:"v-fill-036",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"55.传统戏曲具有悠久的发展历史，并以其独特的表演风格和大众审美取向，在很长一段时期都有着深厚的群众基础。随着社会的快速发展，人们的娱乐方式发生了较大变化，在多元文化形态的冲击下，传统戏曲自身存在的不足也被放大，致使观众群不断减少，剧目创作逐渐萎缩，优秀演员也逐渐流失，传统戏曲受到极大冲击，一度生存艰难。尽管近些年来在政府和社会各界的帮助与扶持下，传统戏曲艺术的生存状况有所好转，但仍旧比较弱势。这段文字意在说明（）。",options:[{label:"A",text:"传统戏曲面临的生存困境"},{label:"B",text:"传统戏曲发展的制约因素"},{label:"C",text:"传承传统戏曲的现实意义"},{label:"D",text:"传统戏曲生存状况的好转"}],answer:"D",explanation:"",tags:["逻辑填空","2022联考A"],year:2022},{id:"v-fill-037",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"56.苔藓是地衣、苔类植物和藓类植物的非正式统称。它们属于非维管植物，没有根部或维管组织，而是通过表面（即叶片）吸收空气中的水分和养分。大多数苔藓只能长到几厘米高。此外，由于苔藓没有根部，它们可以生长在其它植物无法生存之处，比如砖块、墙壁、人行道表面等等。苔藓植物喜欢潮湿阴暗的环境，但它们的栖息地其实十分丰富多样，有些甚至颇为极端，从沙漠到极地都有它们的身影。关于苔藓，这段文字未提及（）。",options:[{label:"A",text:"苔藓生长处其它植物或无法生存"},{label:"B",text:"苔藓植物具有比较顽强的生命力"},{label:"C",text:"极地能够为苔藓提供合适的环境"},{label:"D",text:"非维管构造限制了苔藓生长高度"}],answer:"D",explanation:"",tags:["逻辑填空","2022联考A"],year:2022},{id:"v-fill-038",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"57.“双11购物狂欢节”时，个体的感性思维通常居于主导地位，一些本没有特定目标的消费者容易受到直观行动思维的影响，发生冲动购买行为。同时，在网购过程中，由于支付方式为无现金支付，在感性思维的影响下，很多消费者并没有“支付现金”的感受，认为价格只不过是一个数字，___________。",options:[{label:"A",text:"从而更迫切地积极购买"},{label:"B",text:"反而主动减少购买行为"},{label:"C",text:"进而更容易产生购买行为"},{label:"D",text:"因而更频繁产生购买行为"}],answer:"B",explanation:"",tags:["逻辑填空","2022联考A"],year:2022},{id:"v-fill-039",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"60.近年来，以经典重生为主线的怀旧音乐综艺扎堆亮相，让很多人在歌声中回忆往昔，也让部分年轻观众初听老歌时惊为天人，从此进入到听歌的“考古”岁月。如今的年轻人成长在网络时代，在海量歌单的冲击下，对唱片和专辑已经很陌生了。此时，经典老歌通过怀旧音乐综艺重新进入大众曲库，让不少年轻人开始追寻上世纪八九十年代甚至更早的歌曲。这几年，经典的滚石、宝丽金时代的老歌，越来越被年轻歌迷所认识和了解。这段文字主要介绍（）。若二维码无法识别，给公众号回复“2026国考合集”或“2026省考合集”即可。2022联考B言语理解与表达（山西、重庆、安徽、辽宁、江西、吉林、湖北、陕西）",options:[{label:"A",text:"唱片和专辑对于年轻歌迷来说非常陌生"},{label:"B",text:"怀旧音乐综艺进入听歌的“考古”岁月"},{label:"C",text:"年轻歌迷追寻上世纪八九十年代的歌曲"},{label:"D",text:"经典老歌越来越被年轻歌迷所认识了解"}],answer:"D",explanation:"",tags:["逻辑填空","2022联考A"],year:2022},{id:"v-fill-040",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"59.所有生物都拥有共同的祖先，后来经过漫长的岁月才进化成了各种各样的生物，这是进化论告诉我们的答案。过去，科学家根据生物的外表和骨骼等来推测各种生物的进化历程。但是，近年来随着DNA分析等技术的进步，发现了一些颠覆以往观点、拥有意外亲缘关系的例子。生物世界里存在许多_______________。海豚、海豹和海牛虽然具有非常相似的特征，比如它们都主要生活在水里，体型为流线型等，但实际上这3种动物彼此都不是近亲。海豚和长颈鹿是近亲，而海牛和大象是近亲。",options:[{label:"A",text:"“容貌相似的亲戚”和“毫无相似之处的外人”"},{label:"B",text:"“容貌相似的外人”和“不无相似之处的亲戚”"},{label:"C",text:"“外表相似的外人”和“毫无相似之处的亲戚”"},{label:"D",text:"“外表相似的亲戚”和“不无相似之处的外人”"}],answer:"A",explanation:"",tags:["逻辑填空","2022联考B"],year:2022},{id:"v-fill-041",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"60.一国文明通常要通过典籍、实物和活态三条渠道完成传承。在传统社会中学者关注最多的是前二者，而很少会注意到活态传承。事实上，当一个国家最重要的文明——非物质文化遗产，因其内容、形式、工艺过于复杂，____________。传承人也凭借着他们的“活态传承”，为中华文明的延续作出了属于自己的贡献。",options:[{label:"A",text:"要想通过典籍将非物质文化遗产代代传承，几乎是不可能的"},{label:"B",text:"通过古人的器物、遗址，同样能认识祖先创造的辉煌的人类文明"},{label:"C",text:"用典籍与实物无法传承时，民间常用口耳相传等方式进行“活态传承”"},{label:"D",text:"典籍传承有明显短板，中国典籍大多记载官方历史或文人创作，民间文化鲜有提及"}],answer:"D",explanation:"",tags:["逻辑填空","2022联考B"],year:2022},{id:"v-fill-042",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"44.哈士奇太闹腾、比特犬攻击性太强、拉布拉多很友好……狗狗的性格，似乎已经和它们的品种画上了等号。因此在选择宠物狗时，人们会格外在意它们的品种是否纯正。但研究人员发现，__________________。现代狗的品种在19世纪中后期出现，当时，犬类的主要划分依据是体型特征，比如大丹犬体型巨大，而吉娃娃娇小玲珑。人们通常认为，品种代表着犬类的行为特征，但现在，研究人员认为，没有什么迹象表明这种联系真的存在。",options:[{label:"A",text:"不同品种的狗在行为上有很大差异"},{label:"B",text:"犬类的行为变化可以用品种来解释"},{label:"C",text:"不能根据狗的品种来预测它的行为"},{label:"D",text:"狗的攻击性可能与遗传没什么关系"}],answer:"A",explanation:"",tags:["逻辑填空","2023联考A"],year:2023},{id:"v-fill-043",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"50.现代社会是陌生人社会，以市场经济为基础，更广范围更大规模的交易如跨国贸易，更长距离的往来如海运空运，甚至是跨期买卖如期货交易，不再是在几个熟人之间进行，而是大规模的陌生人社会交往，因此，迫切需要一套交易规则来保障交易的正常进行。这个时候，规则与法律的作用就远远超过熟人社会的习俗礼节与乡规民约。根据这段文字，下列说法正确的是（）。",options:[{label:"A",text:"现代社会通常会依照差序格局决定办事的难易程度"},{label:"B",text:"市场经济需要习俗礼节与乡规民约保障交易的进行"},{label:"C",text:"熟人社会是以家族亲属关系为主轴的社会网络关系"},{label:"D",text:"现代社会人际关系的维系更依赖规约和法律的作用"}],answer:"A",explanation:"",tags:["逻辑填空","2023联考A"],year:2023},{id:"v-fill-044",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"52.近年来，以南海一号沉船博物馆、秦始皇帝陵博物院、安阳殷墟博物馆、海昏侯国遗址博物馆等为代表的考古遗址博物馆，在旅游网站推荐榜单中排名渐次上升。_________________。人们已不再单纯满足于简单的、传统的博物馆参观，而是产生了深入历史场景、触及历史语境的体验需求。",options:[{label:"A",text:"这些变化反映了文化产品的不断更新换代"},{label:"B",text:"新技术带来了文化消费场景的转换与创新"},{label:"C",text:"这一新动态折射了文化消费的深化与转型"},{label:"D",text:"这意味着新型博物馆成为旅游打卡的网红地"}],answer:"A",explanation:"",tags:["逻辑填空","2023联考A"],year:2023},{id:"v-fill-045",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"52.“反对过度消费，倡导理性消费”不是一句空喊的口号。作为消费活动的主体，消费者在面对各种促销信息不断撞击大脑的时候，应当始终把那句老话“买的没有卖的精”记在心头。同时明确自己的消费目标，坚持按需购买，摒弃那种“不凑齐满减就吃亏”“过了这村就没这店”的消费思维，才能避免买了一大堆不需要的东西。正如《断舍离》一书中所说：“不管东西有多贵，有多稀有，_______________，才够强大。”",options:[{label:"A",text:"能够按照内心是否想要来判断的人"},{label:"B",text:"能够按照价格是否划算来判断的人"},{label:"C",text:"能够按照东西是否适合来判断的人"},{label:"D",text:"能够按照自己是否需要来判断的人"}],answer:"A",explanation:"",tags:["逻辑填空","2023联考B"],year:2023},{id:"v-fill-046",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"53.雪域高原，复兴号疾驰在拉林铁路上，藏东南腹地的人们交通出行更加便利；伶仃洋上，港珠澳大桥如飞虹凌波，联通香港、广东珠海、澳门三地，粤港澳大湾区发展跑出加速度；在洋山港，无人驾驶的搬运车来回穿梭，自动化码头大大提高了作业效率，海运效能显著提升……_____________，成为我国交通运输事业取得历史性成就、发生历史性变革的一个生动写照。",options:[{label:"A",text:"放眼神州大地，交通网络内畅外联，涌动着发展的活力"},{label:"B",text:"交通运输业也在全球抗疫、贸易复苏等方面发挥了积极作用"},{label:"C",text:"我国坚持交通先行，迎来由交通大国向交通强国的历史性跨越"},{label:"D",text:"建成立体交通网，连通城乡，连接四面八方，便利人民群众出行"}],answer:"D",explanation:"",tags:["逻辑填空","2023联考B"],year:2023},{id:"v-fill-047",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"60.基础教育是受政治、经济、文化、舆论乃至学界深度影响的领域。学业负担有其自身发生的逻辑链条，义务教育阶段的学业负担问题，既是一个客观存在，在某种程度上也是一个被社会舆论“建构”出来的主观存在。不同家庭、学校和学生所感受的学业负担与政策意图治理的学业负担可能大相径庭。学业负担问题的治理也受到教育内外部多重因素的掣肘，具有极高的挑战性。推动基础教育领域的公私合作而非对立，发挥双方的优势，对包括缓解学业负担问题在内的诸多问题均有意义。",options:[{label:"A",text:"学业负担问题涉及到主客观综合因素"},{label:"B",text:"学业负担有其自身发生的历史与现实逻辑"},{label:"C",text:"学业负担问题受到社会各个层面的深度影响"},{label:"D",text:"缓解学业负担问题有助于推动基础教育发展"}],answer:"D",explanation:"",tags:["逻辑填空","2023联考B"],year:2023},{id:"v-fill-048",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"33.一款零食以前能靠独特口味畅销十几年，这在今天几乎是天方夜谭。新爆款横空出世，模仿者很快______，消费者的新鲜感被迅速透支。当朝生暮死成为网红食品的常态，相比于______的零食巨头，轻资产的中小品牌反而更容易在时代变幻莫测的风向中______。",options:[{label:"A",text:"蜂拥而至 尾大不掉 闪转腾挪"},{label:"B",text:"后来居上 作茧自缚 捷足先登"},{label:"C",text:"青出于蓝 因循守旧 稳操胜券"},{label:"D",text:"龙争虎斗 老气横秋 脱颖而出"}],answer:"D",explanation:"",tags:["逻辑填空","2024联考A"],year:2024},{id:"v-fill-049",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"41.竹秆质地坚硬，其堪与木材媲美的木质特性，来自于初生结构中发达的机械组织和细胞壁木质化的基本组织；木材的木质特性，则来自于年轮式样分布的次生木质部。竹秆外形与其他禾本科草本植物的茎相似，具有明显的节和节间，节数和粗细在出笋时就已基本固定；节附近分布有居间分生组织，节间伸长时，各节分生组织同时活动，竹子迅速拔高；缺少形成层，不能长粗，只能保持“婴儿时期的身材”。竹壁分为竹青、竹肉、竹黄三个部分，竹青含叶绿素呈绿色，可以进行光合作用。根据这段文字，下列说法错误的是（）。",options:[{label:"A",text:"竹秆只能长高不能长粗"},{label:"B",text:"竹子能够进行光合作用"},{label:"C",text:"竹秆的节数在出笋时就已基本固定"},{label:"D",text:"竹子的木质特性来自于次生木质部"}],answer:"C",explanation:"",tags:["逻辑填空","2024联考A"],year:2024},{id:"v-fill-050",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"42.文言和白话是两个相互依存的概念，无文言，也就无所谓白话，但它们并不等同于书面语和口语。受限于语言保存技术，我们现在能感知的古代汉语都是书面上的，包括文言，也包括白话。文言是在先秦口语的基础上形成的古代汉语书面语。先秦两汉的典籍、六朝以后文人仿古写出的作品都属于文言文。白话是汉魏六朝以后，随着语言发展变化而形成的较为接近口语的言语，偶尔也夹杂一些文言成分，较能反映语言的时代性和区域性特点。根据这段文字，下列说法正确的是（）。",options:[{label:"A",text:"汉魏六朝以后的作品都属于白话文"},{label:"B",text:"古代汉语实际上包含白话文的成分"},{label:"C",text:"文言文更能反映语言的时代性特点"},{label:"D",text:"文言与白话分别等同书面语与口语"}],answer:"B",explanation:"",tags:["逻辑填空","2024联考A"],year:2024},{id:"v-fill-051",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"43.在确定是否认识一个人时，我们的大脑会做出三个反应。首先，我们会确认这个人的面部特征，例如他是双眼皮还是单眼皮，高鼻梁还是薄嘴唇；之后，大脑根据这些特征进行人脸识别，判定我们是否认得这张脸；最后再回忆他的名字。简而言之，我们在看到一张脸后，大脑只需简单地识别是否见过；而人的名字藏在记忆的某个角落，我们需要通过检索、回忆等过程，才能最终确定答案，比识别更加复杂。所以______________。",options:[{label:"A",text:"大脑确定是否认识一个人的过程非常的复杂"},{label:"B",text:"记住一个人的名字比记住他的长相要难得多"},{label:"C",text:"大脑根据一个人的面部特征来回忆他的名字"},{label:"D",text:"记忆名字需要与对词语、句子的记忆相联系"}],answer:"D",explanation:"",tags:["逻辑填空","2024联考A"],year:2024},{id:"v-fill-052",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"44.众多民间手艺、戏曲等非物质文化遗产的遗失，与文化传承人缺乏丰厚的收入有关。即便以外部力量进行保护性抢救，往往也只是将其“标本化”，难以恢复其原生活力。_______________。比如，《中国通史》等纪录片在视频平台上收费观看，使传统文化释放出可观的商业价值，纪录片创作方、版权方、播出方实现商业共赢；有花丝镶嵌技艺非遗传承人入驻电商平台，一年多来售出超20万件工艺产品。",options:[{label:"A",text:"文化产业在新的发展能量集聚下将释放出更多精彩"},{label:"B",text:"正是对传统文化的创新演绎成就了文化产业的发展"},{label:"C",text:"只有新媒体技术的加持，才能推动传统文化的传播"},{label:"D",text:"只有文化消费市场活跃，传统文化创作才能有动力"}],answer:"A",explanation:"",tags:["逻辑填空","2024联考A"],year:2024},{id:"v-fill-053",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"44.如今无论什么季节，任何水果都能随时买回家尝鲜，很多人对此并不赞同，理由是反季水果的种植过程中总会有不利于健康的因素，因此他们在选购水果的时候，会侧重购买当季、当地产的水果。但是，果蔬中是否存在不利于健康的因素，与自然栽种还是大棚栽种没有必然联系。随着现代化农业技术的推广应用，大棚栽种水果技术越来越成熟，所有的保鲜剂、食品添加剂、植物生长调节剂，只要是国家相关标准允许使用的，且在规定的用量下，对人体健康是没有危害的。这段文字旨在说明（）。",options:[{label:"A",text:"人们倾向于购买当季当地产的水果"},{label:"B",text:"反季水果在种植过程中会产生不利于健康的因素"},{label:"C",text:"水果是否存在不利于健康的因素与栽种方式的选择无关"},{label:"D",text:"应加强现代农业技术的推广应用，减少添加剂对健康的危害"}],answer:"A",explanation:"",tags:["逻辑填空","2024联考B"],year:2024},{id:"v-fill-054",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"45.长期以来，我们将沙质土壤景观统称为“沙漠”，常与荒凉、沙尘暴等相联系，甚至认为是地球的皮肤癌。但事实上，“山水林田湖草沙”是生命共同体。沙地依靠渗入地下深处的土壤水分，长出了稀疏的乔木、各类灌木及草本，形成了疏林草原、灌丛草原景观，________________。其生物多样性——如毛乌素沙地是鄂尔多斯高原植物与动物集中分布区，几乎涵盖了鄂尔多斯全部物种。但毕竟受降水限制，大部分沙地土壤水分尚未达到较密的森林生长的基本水分要求，但局部水分条件较好的地区亦有分布。沙漠同样如此，特别是沙漠湖泊湿地，是沙漠区宝贵的生物资源宝库。",options:[{label:"A",text:"也具有重要的生态价值"},{label:"B",text:"形成重要的防风固沙屏障带"},{label:"C",text:"构成了自然生态系统必不可少的要素"},{label:"D",text:"其生物多样性往往高于同地带植被区"}],answer:"C",explanation:"",tags:["逻辑填空","2024联考B"],year:2024},{id:"v-fill-055",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"46.新农人，不同于传统农民，也异于新型职业农民，他们多是从城市回流农村的新群体。如果说过去大部分年轻人以跳出农门为奋斗目标之一的话，近年来，跳回农门正在成为新时尚。新农人带来了新技术、新商业模式和运营理念，创造了新的就业机会和空间，丰富并拓展了农村经济业态。但在现实中，新农人融入农村社会网络，激活产业网络并没有那么容易。不少人虽然在物理意义上返乡回乡了，但在社会关系上仍是“异乡人”。正如不少调研所显示的，新农人不了解农村，不知道如何与农民打交道，难以有效嵌入当地产业网络开展分工合作。这段文字主要说明了（）。",options:[{label:"A",text:"新农人，回得去并不等于融得进"},{label:"B",text:"新农人需补短板，否则创业难成"},{label:"C",text:"新农人具备新理念，掌握新技术"},{label:"D",text:"时代呼唤更多新农人回农村创业"}],answer:"B",explanation:"",tags:["逻辑填空","2024联考B"],year:2024},{id:"v-fill-056",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"47.元素周期表是化学科学的基石，在化学发展史上具有里程碑意义。作为元素周期表中的“住户”，元素的发现几乎与人类文明相伴。像铁、铜、金、银等容易以单质形态存在的元素发现得最早，之后从铁器时代到青铜时代，从炼金术到电解技术，从核辐射到核裂变，_____________，新“住户”不断占据各自的位置。直至今日，仍然有新的元素被发现（合成），而且关于元素在生命起源、物种进化中的作用以及元素如何精准调控材料性能及生命过程等仍然是科学家们非常关注的科学问题。",options:[{label:"A",text:"元素周期表逐步被填充并扩展"},{label:"B",text:"元素周期表被有序地组织起来"},{label:"C",text:"元素周期表得到较完美的呈现"},{label:"D",text:"元素在周期表不同行列排列着"}],answer:"A",explanation:"",tags:["逻辑填空","2024联考B"],year:2024},{id:"v-fill-057",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"51.碳纤维是由有机纤维经过一系列热处理转化而成，含碳量高于90%的无机高性能纤维，是一种力学性能优异的新材料，其比重不到钢的五分之一。碳纤维树脂复合材料抗拉强度是钢的7至9倍，还具有出色的耐热性、优秀的抗腐蚀性与抗辐射性。以碳为主要原料，以碳纤维复合材料、石墨烯等为核心的新一代复合材料是21世纪最具应用前景的新材料，可应用于飞机结构材料、人工韧带等身体代用材料以及火箭外壳、工业机器人等领域，但碳纤维复合材料发展也面临着高质量树脂基材缺乏等发展瓶颈问题。根据这段文字，下列说法正确的是（）。",options:[{label:"A",text:"碳纤维是一种含碳量高的有机纤维"},{label:"B",text:"碳正成为 21 世纪的主导型先进材料"},{label:"C",text:"碳纤维树脂复合材料的抗拉强度优于钢"},{label:"D",text:"碳纤维树脂复合材料是一种最耐热且最坚硬的材料"}],answer:"D",explanation:"",tags:["逻辑填空","2024联考B"],year:2024},{id:"v-fill-058",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"52.经济活动的可持续性和相关金融资产的价值依赖于生物多样性和环境提供的生态系统服务。与气候变化类似，生物多样性丧失也是本世纪面临的最大危机之一。导致环境恶化和气候变化的罪魁祸首是大量不考虑环境影响、破坏生物多样性、只顾赚钱的投资活动。因此，____________。",options:[{label:"A",text:"在保护生物多样性方面金融业有着不可推卸的责任"},{label:"B",text:"人类将面临气候变化和生物多样性丧失的巨大危机"},{label:"C",text:"应逐步建立对金融机构管理的监管框架和稳定机制"},{label:"D",text:"导致环境恶化的根本原因是大量经济活动的可持续性"}],answer:"A",explanation:"",tags:["逻辑填空","2024联考B"],year:2024},{id:"v-fill-059",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"57.在机场过安检时，有时会遇到这样的情景：安检人员用一张白色的小纸片在你的手提行李、电子设备，甚至你的衣服上擦拭一遍，再将试纸放入一旁的仪器中。这张白色的小纸片其实是一种专门设计的爆炸物痕量检测纸，用于探测行李或物品表面是否残留有爆炸物的痕迹。它的使用起源于对航空安全的严格要求，尤其是在现代航空业面对的恐怖主义威胁日益增多的背景下，痕量检测技术已成为机场安检系统中的重要组成部分。这段文字接下来最不可能谈及的是（）。",options:[{label:"A",text:"爆炸物痕量检测纸的工作原理"},{label:"B",text:"安检中使用痕量检测纸的利弊"},{label:"C",text:"机场采用痕量检测技术的背景"},{label:"D",text:"候机楼发现爆炸物的处置程序"}],answer:"B",explanation:"",tags:["逻辑填空","2025联考A"],year:2025},{id:"v-fill-060",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"58.随着天气越来越冷，早晨起床也变得越来越难，睡醒了总想赖一会儿床，有人觉得这就是因为懒。其实，_____________。作为恒温动物，人类有最适宜的温度区间，一夜的睡眠让被窝里温暖又舒适，但被窝外却是寒气袭人。寒冷意味着需要消耗更多的能量，但如果继续躺在床上就可以保持体温。这时，刻进基因里的节能机制让人倾向于选择待在温暖的被窝里，这种机制来自于住在山洞中恐惧饥寒的祖先们的经验，即尽可能地保存能量，并保护身体免受寒冷的伤害。",options:[{label:"A",text:"这还是人类祖先留下的保命本领"},{label:"B",text:"苏醒的过程也会受到环境温度的影响"},{label:"C",text:"不妨耐心等一会儿再起床，让身体先“开机”"},{label:"D",text:"适当赖床可以给身体足够的时间适应室内外的温度差异"}],answer:"D",explanation:"",tags:["逻辑填空","2025联考A"],year:2025},{id:"v-fill-061",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"59.郑和大航海发生在中国军事科技实力遥遥领先的背景下，郑和率领两百余艘船、两万多名将士的大舰队，实力远超大航海时代两三艘船、百余人的小船队，军事实力更是远超途经的国家和地区，但郑和船队坚持“共享太平之福”“敦睦邦交”“强不凌弱”的原则，奉行“厚往薄来”的政策，从来没有以大欺小，倚强凌弱，没有掠夺一两黄金白银，没有发动一场军事侵略，也没有占领一寸海外殖民地。“郑和大航海”_____________。",options:[{label:"A",text:"在中外交流交往中发挥了积极的作用"},{label:"B",text:"为中国的发展创造了稳定的国际环境"},{label:"C",text:"是中华民族一脉相承的和平基因的最好例证"},{label:"D",text:"为推动构建海洋命运共同体提供了中国方案"}],answer:"A",explanation:"",tags:["逻辑填空","2025联考A"],year:2025},{id:"v-fill-062",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"60.枯木是自然界中凋枯衰朽之木的总称。宋诗中展现出各种枯木之姿，不仅丰富了诗歌的审美内蕴，还折射出宋人独特的精神追求。_____________。宋代社会掀起一股尚“枯”趣味的审美潮流。在日常生活领域，“三苏”开创了清供枯木假山的潮流，枯态花卉、寒山枯林受到士人们的欣赏；在艺术创作领域，士人们在书画创作中运用枯笔技法、追崇枯瘦书体，开创了枯木题材的绘画；在诗歌批评领域，宋代出现了“枯淡”“枯劲”等一系列含“枯”的诗论概念。从日常生活到文学艺术，“枯”成为宋人的重要美学命题。",options:[{label:"A",text:"枯木意象寄托了宋人丰富的情思意蕴"},{label:"B",text:"对枯木的思考映现出艺术家的创作情感"},{label:"C",text:"枯木意象与宋代社会的审美文化息息相关"},{label:"D",text:"诗歌中的枯木意象具有深邃的思想文化内涵"}],answer:"D",explanation:"",tags:["逻辑填空","2025联考A"],year:2025},{id:"v-fill-063",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"54.上门代厨、上门收纳整理、上门推拿、上门养老……近年来，各类上门服务新业态涌现，为市场经济输入新鲜血液。但“上门经济”并非只有红利没有烦恼。调查发现，目前“上门经济”面临监管存在盲区、消费者维权难、取证溯源难等问题，亟待加强规范引导。规范是保障行业健康有序发展、维护各方合法权益的基础。只有把规矩立起来，加强规范引导，才能促进“上门经济”良性发展。最适合做这段文字标题的是（）。",options:[{label:"A",text:"“上门经济”规范有序方能行稳致远"},{label:"B",text:"“上门经济”并非只有红利没有烦恼"},{label:"C",text:"“上门经济”为市场经济输入新血液"},{label:"D",text:"“上门经济”既要敞开门也要守好门"}],answer:"A",explanation:"",tags:["逻辑填空","2025联考B"],year:2025},{id:"v-fill-064",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"55.蝶翅是承载着复杂功能的器官。例如，蝶翅上的鳞片能够帮助蝶类调控体温，主要作用原理是通过张开或闭合鳞片，调节入射光线的角度，减少或增加对阳光中热能的吸收，将体温维持在正常范围。雄蝶的蝶翅可能具有一些特殊的发香鳞，这些发香鳞混于普通鳞片之中，具有腺体，可产生挥发性的信息素以便在求偶过程中吸引雌蝶。此外，很多蝶翅的图案和花纹还具有吓退捕食者或转移捕食者攻击目标的作用。可见，______________，在蝶类生命活动中发挥着不可或缺的作用。",options:[{label:"A",text:"鳞片和多形态的翅纹提高了蝴蝶的自我保护能力"},{label:"B",text:"蝶翅鳞片具体功能因蝴蝶种类不同而有差异"},{label:"C",text:"具有多种功能的蝶翅是成为拟态高手的关键"},{label:"D",text:"蝶翅集控温、求偶、御敌等功能于一体"}],answer:"D",explanation:"",tags:["逻辑填空","2025联考B"],year:2025},{id:"v-fill-065",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"56.传统文化与数字文明相遇，在“尼山对话”专题活动中获得了更为直观的体现。“礼”有了形象，“乐”有了声音，居延汉简、敦煌遗书可以数字巡游，阿房宫、未央殿可以“云端漫步”，我们有了一个全新的角度审视传统文化。传统文化的数字化叙事过程，______________。传统文化依托数字技术，在内容互嵌基础上创新转化为符合人们文化体验需要的新模式，不仅连接过去与现在，也将在未来展现出更强大的感染力与魅力。",options:[{label:"A",text:"构筑了国家文化软实力的新优势"},{label:"B",text:"成为人类文明进步的一个重要标志"},{label:"C",text:"为人工智能技术与传统文化的融合发展开辟新道路"},{label:"D",text:"是对中华优秀传统文化内容的再创造与再阐释的过程"}],answer:"D",explanation:"",tags:["逻辑填空","2025联考B"],year:2025},{id:"v-fill-066",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"29.很长时间以来，在戏曲传承中遇到的最大挑战就是观众流失，尤其年轻的观众越来越少。这其中一个重要因素，就是戏曲在当下的“打开方式”还比较单调，不能满足当代人的需求。什么样的“打开方式”才能吸引人？法门之一就是“融入生活”。作为优秀的传统文化，戏曲代表着以往的生活方式，如今时代变化，有些生活方式虽然和人们已经脱节，可是有些元素还能为人们所用。“第一套戏曲广播体操”在央视戏曲春节晚会上播出，受到热捧，许多人争相学习，就是因为这套广播体操契合了现代人锻炼身体的需求，同时又能兼顾艺术魅力的体验。这段文字意在强调，戏曲传承应该（）。",options:[{label:"A",text:"注重传播优秀的文化"},{label:"B",text:"改变单调的表现方式"},{label:"C",text:"努力融入人们的生活"},{label:"D",text:"兼顾民族性和世界性"}],answer:"B",explanation:"",tags:["逻辑填空","2020山东"],year:2020},{id:"v-fill-067",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"30.众所周知，人类被一个强烈的地磁场所保护着不受各种太空辐射的侵害。正因为这个地磁场的偏转作用，各种有害的辐射都被阻挡在外，无法到达地面。这个地磁场被认为是由地核周围的液态岩浆受热流动所产生的。________________。那就是，液态岩浆形成和流动都建立在炽热地核的基础上，而研究表明地核的年龄仅仅只有十亿年，但是维系地球生命的保护伞——地磁场，却至少已经存在了四十亿年之久。",options:[{label:"A",text:"这一观点确实加深了人类对地球结构的理解"},{label:"B",text:"围绕地磁场的形成还有一种相反的观点"},{label:"C",text:"关于地磁场的一个悖论科学家们却一直未能解释"},{label:"D",text:"但人们对于地磁场的年龄还存在一些疑问"}],answer:"C",explanation:"",tags:["逻辑填空","2020山东"],year:2020},{id:"v-fill-068",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"31.中国古代称外国为“番”。出于表示尊敬、臣服等原因，这些番邦会派使节来朝见皇帝。众多番邦使节云集朝堂，为了便于皇帝逐一认识，负责典礼的大臣就将各位使节分成两列，皇帝按照先后次序，先左后右与使节寒暄交谈，依次类推。交谈之前，典礼官都会报告这些番邦国家的称号，即所谓的“番号”，因此番号就有了依次编号的意味。在现代汉语中，番号一般特指部队编号，主要是按照部队的性质、编制序列和数字顺序授予的部队名号。这文字主要介绍了（）。",options:[{label:"A",text:"现代部队编号的起源"},{label:"B",text:"“番号”一词的来源及含义"},{label:"C",text:"古代番邦朝见的热闹场景"},{label:"D",text:"古代皇帝接待使节的礼仪程序"}],answer:"B",explanation:"",tags:["逻辑填空","2020山东"],year:2020},{id:"v-fill-069",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"32.这些年西汉纸不断出土，从材料上看，西汉纸大多夹带许多未被捣碎的纤维团，这种纸制作粗糙，组织松散，纸浆分布不匀，透眼较多，不太适于落笔着墨，书写起来也不顺畅。西汉纸大多不平整，像被揉搓过一样。出土的很多纸上都没有字，即便有字，也是写在纸的右下角，常见的有“付子”“细辛”等。经考证它们基本都是汉代的药名。于是有学者推论，如果这类纸用于包装药材，那些写在纸角的字，恰好就会露在药包的表面。这样看来，________________。",options:[{label:"A",text:"原来早在蔡伦之前纸就已经被发明出来了"},{label:"B",text:"纸张成为主要书写工具经历了漫长过程"},{label:"C",text:"西汉的古纸极有可能主要用来包装东西"},{label:"D",text:"我国古代造纸起源与中药学发展不无关系"}],answer:"B",explanation:"",tags:["逻辑填空","2020山东"],year:2020},{id:"v-fill-070",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"22.彩色摄影是饱含缤纷色彩的造型语言，黑白摄影是经典的、表达独特艺术思考的视觉化工具，它们之间不存在哪个更好、表现力更强的问题。无论是使用经验，还是作品所呈现的视觉效果，这两者都是完全不同的事物。今天的黑白摄影，即使不再是摄影艺术性和技术性的代表，也并不是什么过时的事物。黑白摄影仍具有自身独特的语言和能力，发挥着自己的特色，展现着新的可能，依然是解决、分析、阐述艺术问题的方法手段和需要研究探索的课题。这段文字意在说明，黑白摄影（）。",options:[{label:"A",text:"与彩色摄影不具有可比性"},{label:"B",text:"在当今语境下仍有较高的艺术价值"},{label:"C",text:"需要与时俱进不断发展"},{label:"D",text:"自身具有独特的艺术评价标准"}],answer:"B",explanation:"",tags:["逻辑填空","2021山东"],year:2021},{id:"v-fill-071",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"23.随着越来越多的国家投入到军用机器人的研究与开发中去，世界已在不知不觉中滑进了一场机器人军备竞赛。毋庸置疑，军事机器人相比于士兵，在功能、体能、效能方面具有极大优势。它可以同时承担多项复杂任务，作战更加持久，在程序设定完成后能够高效精准地达成目标，失误率较低。特别是完全自主机器人，与人类战士相比，具有持线作战时间长、反应能力快、生存能力强等优势，将会进一步增加战争的强度。然而_________________：参战的自主机器人到底是不是战斗员？又应当承担何种战争责任？",options:[{label:"A",text:"自主机器人在战争中的角色引人深思"},{label:"B",text:"机器人参战可以重塑未来战争的图景"},{label:"C",text:"机器人军备竞赛的发展前景尚不明朗"},{label:"D",text:"有关战争责任的伦理问题也随之出现"}],answer:"A",explanation:"",tags:["逻辑填空","2021山东"],year:2021},{id:"v-fill-072",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"24.研制超材料就是按照特定的规则组合，搭配出不同电磁响应属性的人工复合材料。这些材料的属性除由材料本身决定外，还与其结构的形状、尺寸、排列和组合方式等紧密相关。通过改变超材料关键位置的结构和尺寸，人们就可以像搭积木一般实现对光波、雷达波、无线电波、声波乃至地震波的任意弯曲和精细“裁减”。比如，研究人员借助超材料薄层能让光线绕过物体的属性，开始研究使物体无影无踪的“隐身斗篷”。这段文字主要介绍了超材料的（）。",options:[{label:"A",text:"研制原理"},{label:"B",text:"应用领域"},{label:"C",text:"分类标准"},{label:"D",text:"设计意图"}],answer:"D",explanation:"",tags:["逻辑填空","2021山东"],year:2021},{id:"v-fill-073",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"25.早期人们对质量的认识并不清晰，质量管理专家给出的质量定义也不统一，比较有代表性的定义是“质量是产品符合规定要求的程度”，这是从生产角度来定义的质量，即强调产品要达到规定要求或标准。20世纪60年代美国质量管理专家提出，质量是产品的适应性，强调产品要适合用户的使用需要，任何产品如果不能满足顾客需要，不管它多么符合产品标准，也不是好的质量，这是人们首次从用户的角度认识和定义质量。__________________，这是质量观的一次重大转变。",options:[{label:"A",text:"从满足生产需求转变到供给需求"},{label:"B",text:"从对产品的保量要求转变到保质要求"},{label:"C",text:"从强调产品转变到强调服务"},{label:"D",text:"从关注生产方转变到关注需求方"}],answer:"B",explanation:"",tags:["逻辑填空","2021山东"],year:2021},{id:"v-fill-074",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"32.在游戏的世界里，人们不用承担现实生活中同样行为造成的后果，游戏输了可以点击“再来一次”一键复活。因此游戏提供了一种低成本低风险的自我实现方式。当个体在现实生活中受挫，游戏可以成为一种短暂的对现实世界的逃避。在游戏里建立社交关系，不断升级，提供了持续的挑战和个体存在的意义。最适合做这段文字标题的是（）。",options:[{label:"A",text:"游戏成瘾，如何解决"},{label:"B",text:"游戏社交：安全无负担"},{label:"C",text:"现实越受挫，游戏越成瘾"},{label:"D",text:"游戏：另一种“自我实现”"}],answer:"B",explanation:"",tags:["逻辑填空","2021山东"],year:2021},{id:"v-fill-075",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"33.随着我国科技对经济社会发展贡献率的增大，以及科技介入生活程度的加深，普通人与科技的关系也变得更加密切。科普走进生活，越来越成为人们的普遍期待。而这又对科普创新提出了更高的要求。科普创新当然首先是要及时更新科普的理念和内容，把日新月异的科技发展成果通俗易懂地告诉民众。同时，它也意味着科普形式和手段的创新。增添文艺的元素，则是其题中应有之义。______________。老一辈科学工作者十分善于借用文学艺术的力量。例如，当我们翻阅竺可桢先生《说飓风》《说云》等科普文章时，就会被其准确而又生动的文字所折服。",options:[{label:"A",text:"人们对科普作品文艺性的期待越来越高"},{label:"B",text:"文学艺术是推动科普创新的重要驱动力"},{label:"C",text:"事实上，科普本身就具有文学性"},{label:"D",text:"如何兼顾科普内容和形式的创新是当务之急"}],answer:"D",explanation:"",tags:["逻辑填空","2021山东"],year:2021},{id:"v-fill-076",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"34.对于古希腊人来说，各种形式和内容的比赛活动无所不在，凡是有竞赛的地方就有规则的存在。体育比赛有严格和严密的竞赛规则，裁判员在赛场上依据规则来进行判罚，只有如此才能产生没有任何争议的优胜者。这些活动的背后，如何用好的规则引导竞争，规范竞争，使人向善，使社会更为公正，是古希腊思想家们热衷探讨的话题。这段文字意在说明（）。",options:[{label:"A",text:"古希腊人强调竞争中规则的重要性"},{label:"B",text:"公平是古希腊思想家们持续关注的话题"},{label:"C",text:"遵守规则是古希腊体育比赛的核心理念"},{label:"D",text:"严密的规则才能实现社会的公正"}],answer:"D",explanation:"",tags:["逻辑填空","2021山东"],year:2021},{id:"v-fill-077",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"35.研究发现，地震前岩石中氡值会有明显变化，就此可对地壳活动作出研判。氡观测是国际上普遍认可的地震监测手段之一，氡值是我国地震观测台网中最重要的测项之一。地震行业氡观测仪主要采用固体氡源进行校准，但固体氡源属于受国家严格监管的放射类源。由于存在运输不便等问题，氡观测仪无法实现全国统一校准。由于监测仪器标准不统一，A地区测出的氡气含量可能跟B地区测出的不一样。这样的话，测出的数据就没有意义。因此，_________________。",options:[{label:"A",text:"氡观测仪器难以在全国范围内广泛应用"},{label:"B",text:"地震监测手段丰富和多元化"},{label:"C",text:"地震行业亟需统一氡观测仪器的标准"},{label:"D",text:"在不同地区应采用不同的地震监测"}],answer:"D",explanation:"",tags:["逻辑填空","2021山东"],year:2021},{id:"v-fill-078",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"11.中国山水画中蕴含极其丰富的内涵，天人合一的理念，逸人志士的情怀，______的追求，______的境界，______的灵魂，中国绘画的丰满性与深刻性，两个字“清气”，是自然、社会、灵魂中一切事物的结晶。",options:[{label:"A",text:"萧疏清远 空灵荒寒 耿介拔俗"},{label:"B",text:"耿介拔俗 慷慨豪放 空灵荒寒"},{label:"C",text:"慷慨豪放 萧疏清远 耿介拔俗"},{label:"D",text:"空灵荒寒 慷慨豪放 萧疏清远"}],answer:"A",explanation:"",tags:["逻辑填空","2023山东"],year:2023},{id:"v-fill-079",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"15.文献连接着无机和有机世界，揭示着各时代的人事关系，珍藏着鲜为人知的记忆与智慧，是民族成长和发展的全面反映，是我们不容忽视的一类独特产品或重要印记。然而颇为遗憾的是，如今大量文献或躺在收藏机构的角落里______，或封存于书库______。近年来，“展览”作为收藏机构信息利用和创新服务的一大亮点，以视觉化、生动性和体验感等特点吸引了众多观众。但目前不少展览只是陈列文献，并未在深入解读文献所载信息后进行视觉转化，忽视了受众的识读困难、文献的真正价值及媒介的功能发挥，导致展览与观众“对话”受阻，展览收效甚微，文献作为“物证”的利用效果______。",options:[{label:"A",text:"无人问津 不见天日 不尽如人意"},{label:"B",text:"不见天日 无人问津 称心如意"},{label:"C",text:"暗无天日 束之高阁 差强人意"},{label:"D",text:"置之不理 暗无天日 不遂人愿"}],answer:"A",explanation:"",tags:["逻辑填空","2023山东"],year:2023},{id:"v-fill-080",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"24.新征程上看“贯彻”，要铺开“全面覆盖”的广度。____________。党的二十大所作出的决策部署涵盖改革发展稳定、内政外交国防、治党治国治军各方面，谋划和推动地区部门工作要以贯彻党中央决策部署为前提，始终坚持系统观念，牢固树立全国一盘棋思想，创造性开展工作，做到既为一域增光，又为全局添彩。",options:[{label:"A",text:"空谈误国，实干兴邦"},{label:"B",text:"不谋全局者，不足谋一域"},{label:"C",text:"世异则事异，事异则备变"},{label:"D",text:"路虽远，行则将至"}],answer:"D",explanation:"",tags:["逻辑填空","2023山东"],year:2023},{id:"v-fill-081",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"32.清代科举文体中的“策”与“论”实为两种文体，常为人所混淆，甚至误以为殿试及乡会试的“策问”就是“策论”。事实上，自清前期乡会试的孝经论、性理论在乾隆时期被取消后，直到清末科举改制，“论”才重新回到乡会试之中，且因其专试历代史事、清朝掌故，而形成了一种全新的科举文体，即“中国政治史事论”。作为用以选才的科举文体，“中国政治史事论”固然脱胎于古文的“论”，却与一般的政论、史论有着明显的差异。它受制于科场程式的束缚，文学色彩略淡，政治意味更浓。这正是中国古代“文以载道”的理论与以文章考察士子才、学、行的科举制度形成互动影响的典型案例。这段文字接下来最可能介绍（）。",options:[{label:"A",text:"政治史事论科举文体的特点"},{label:"B",text:"清代选才规则及选才观念的转变"},{label:"C",text:"“文以载道”的理论对科举制度的影响"},{label:"D",text:"清代科举制度的历史变迁与社会影响"}],answer:"B",explanation:"",tags:["逻辑填空","2023山东"],year:2023},{id:"v-fill-082",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"33.众所周知，南朝是一个皇权重新集中、士庶升降变化剧烈的时代。皇帝为了削弱和限制高门士族，必定要扶持次等士族和寒门。后两者为了政治进身也必然依附皇权。在南朝，文学才能是衡量世族的一条重要标准，出身寒门庶族的帝王为全方位强化权威形象而努力跻身文人行列，同时拔擢与其门第身份相近的次等士族和寒门文士。正是在这样的背景下，________________。彭城刘氏、兰陵萧氏、彭城到氏、吴兴沈氏、吴兴陈氏等家族，他们在通过武力夺取政权或靠积累军功获取了足够的政治资源，都表现出生活方式“士大夫化”的倾向。",options:[{label:"A",text:"皇权重振加速了次等士族的迅速兴起"},{label:"B",text:"寒门庶族大都参与到激烈的权力争斗"},{label:"C",text:"提升文化修养成了所有寒门庶族的共同追求"},{label:"D",text:"庶族不满足于对门阀大族手中政治权利的分享"}],answer:"D",explanation:"",tags:["逻辑填空","2023山东"],year:2023},{id:"v-fill-083",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"29.从物质形态上看，广义的历史典籍版本包括甲骨文、金文、简帛、石刻、唐宋元明清及近代的手写本、印刷品等，可谓______。此外，还有大量的出土文物、地上地下遗址、文化遗存，以及祖祖辈辈______的历史传说、民风民俗、家风家训等，这些共同构成“广阔的文化空间”，也是一座巨大的______的文化宝藏，蕴藏着中华文明生生不息的密码。",options:[{label:"A",text:"琳琅满目 一脉相承 独一无二"},{label:"B",text:"汗牛充栋 口耳相传 无与伦比"},{label:"C",text:"浩如烟海 倾囊相授 包罗万象"},{label:"D",text:"卷帙浩繁 言传身教 价值连城"}],answer:"B",explanation:"",tags:["逻辑填空","2024山东"],year:2024},{id:"v-fill-084",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"30.我们的节日文化，总在传承发展中______。除夕守夜的年俗，从围炉夜话到一起看春晚，再到边看春晚边晒年夜饭，形式越来越丰富；端午节不少地方推出读诗、赛诗活动，诗意过节过出清新感。从更广视角看，中华文明的浩荡长河，既有深沉厚重的历史积淀，也有______的实践再造，还有奔腾澎湃的创新汇流。因为坚守正道，所以敢于______、海纳百川；因为主动求变，所以时代气息更浓、生机活力更足。",options:[{label:"A",text:"另辟蹊径 点铁成金 革故鼎新"},{label:"B",text:"别具一格 千锤百炼 集思广益"},{label:"C",text:"精彩纷呈 脱胎换骨 标新立异"},{label:"D",text:"别开生面 大浪淘沙 推陈出新"}],answer:"C",explanation:"",tags:["逻辑填空","2024山东"],year:2024},{id:"v-fill-085",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"31.蒙内铁路是肯中共建“一带一路”的旗舰项目，为肯尼亚创造了约4.6万个就业岗位，推动了沿线地区的城镇化进程，促进了肯中双边经贸合作。据统计，蒙内铁路2022年运送旅客239万人次，高于2021年的199万人次，客运服务收入达26亿肯尼亚先令。蒙内铁路货运量同样呈现上升趋势，2022年共运输超过600万吨货物，货运服务收入超过126亿肯尼亚先令。随蒙内铁路建成的内罗毕内陆集装箱港和奈瓦沙内陆集装箱港改善了货物装卸和运输条件，促进了蒙内铁路货运量的增长，完善了肯尼亚物流体系，增强了整个区域的竞争力。关于蒙内铁路，下列哪种说法可以从文中得到支持？（）",options:[{label:"A",text:"促进了肯尼亚旅游业的繁荣"},{label:"B",text:"对肯尼亚港口建设有推动作用"},{label:"C",text:"2022 年客运较上年的收益情况"},{label:"D",text:"持续为肯尼亚发展振兴注入动力"}],answer:"B",explanation:"",tags:["逻辑填空","2024山东"],year:2024},{id:"v-fill-086",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"32.从来没有百分之百成功的基础研究。______________；没有大量错误作台阶，也就登不上最后正确结果的高座。对于“失败”的每一次宽容，都在涵养敢担风险、勇攀高峰的科研生态，孕育下一次创新的成功。而一旦“慢跑”中的科学家拨动到灵感的琴弦，看似“无用”的原始创新成果就能如核裂变般爆发出巨大能量，推动文明进程的跨越式发展，以浩荡之势开辟崭新天地。",options:[{label:"A",text:"自由探索很容易“失败”"},{label:"B",text:"只有宽容失败，才有从容探索"},{label:"C",text:"每一次颠覆式创新背后，都是一场“慢跑”"},{label:"D",text:"基牢不牢，决定了科学大厦建得高不高"}],answer:"B",explanation:"",tags:["逻辑填空","2024山东"],year:2024},{id:"v-fill-087",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"44.随着户籍制度改革深入推进，全国31个省份都出台了户籍改革意见，全面取消农业户口。这标志着二元户籍制度退出历史舞台，意味着在中国存在了半个多世纪的“城里人”和“乡下人”户口身份识别将不复存在，农民不再是身份，而是职业。当农民成为一种职业，新的理念、新的经营知识等将会培育和造就数以亿计的有文化、懂技术、善经营、会管理的新型职业农民。这段文字接下来最有可能讲述的是（）。",options:[{label:"A",text:"与传统农民相比新型职业农民的素养与能力"},{label:"B",text:"户籍制度改革给新型职业农民带来的便利"},{label:"C",text:"国家给新型职业农民提供的政策支持"},{label:"D",text:"新型职业农民面临的挑战与发展困境"}],answer:"A",explanation:"",tags:["逻辑填空","2024山东"],year:2024},{id:"v-fill-088",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"45.社火原本是属于农民的自演自娱活动，来源于古人对土地和火的崇拜。社，即土地神；火，即火祖，也即火神。农业中国，是土地给了人们立足之本。《礼记·祭法》载：“共工氏之霸九州也，其子曰后土，能平九州，故祀以为社。”火可以熟食、取暖，是人类创立文明的显著标志。崇拜土地与火________________，这逐渐演化成了规模盛大、内容繁复的传统民间娱乐活动。",options:[{label:"A",text:"表达了古人对社与火的朴素情感"},{label:"B",text:"奠定了农业文明发展的民俗基础"},{label:"C",text:"产生了祭祀社与火的风俗"},{label:"D",text:"体现了古人土地为本的理念"}],answer:"C",explanation:"",tags:["逻辑填空","2024山东"],year:2024},{id:"v-fill-089",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"46.新研究发现，向日葵花粉能帮助熊蜂抵抗一种常见寄生虫感染。实验中，将向日葵花粉的外壳与其内部的代谢物分离，分别添加到美洲东部熊蜂的食物中。结果显示，仅添加花粉所含的代谢物对抵抗熊蜂短膜虫感染没有效果；添加花粉外壳的抗感染效果与添加完整的向日葵花粉颗粒相当，感染率可降低87%。苍耳、蒲公英的花粉也能降低感染率。下列哪项说法不能从文中得到支持？（）",options:[{label:"A",text:"可以使用向日葵花粉内部代谢物来减少蜜蜂寄生虫感染"},{label:"B",text:"向日葵花粉外壳物质在帮助蜜蜂抵抗寄生虫感染上有效果"},{label:"C",text:"向日葵花粉外壳和内部代谢物的作用是不同的"},{label:"D",text:"苍耳、蒲公英的花粉有类似向日葵花粉的作用"}],answer:"B",explanation:"",tags:["逻辑填空","2024山东"],year:2024},{id:"v-fill-090",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"47.近年来，从新能源汽车下乡到绿色智能家电下乡，一系列高品质工业品从“稀罕物”变成“必需品”，有效提升了农民生活水平。多年经验告诉我们：工业品下乡绝不意味着“积压品下乡”，更不能拿质次价廉的商品糊弄消费者，_______________。比如，有的家电企业看到，一些地区的农民喜欢把洗衣机放在露天小院使用，于是重新设计洗衣机产品外壳，解决了下雨导致的生锈问题；有的企业专门推出能在较大电压波动范围内正常启动的冰箱，适应了部分农村地区的环境和条件。惠民生、增福祉是工业品下乡的政策初衷。牢牢把握这个基点，才能让“下乡”的动能更足、活力更强，真正提振消费、拉动内需。",options:[{label:"A",text:"要深入调研农村消费群体，了解其实际需求"},{label:"B",text:"高品质满足农村地区消费者实际需求才是硬道理"},{label:"C",text:"要统筹兼顾，破解难题，切实激发家电企业的积极性"},{label:"D",text:"充分发挥乡村消费市场的重要作用，用好工业品下乡政策"}],answer:"A",explanation:"",tags:["逻辑填空","2024山东"],year:2024},{id:"v-fill-091",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"50.中华民族自古崇尚读书，讲究格物致知、诚意正心。我们走过书信时代，经过电邮时代，来到读“屏”时代，网页挤占书页，“输写”代替书写。我们无法回到“从前慢”的过去，但也不能丢失知识的传承、文化的涵养、精神的赓续。加强数字资源平台建设，开展青少年学生读书活动，是把数字技术这一“最大变量”转化为阅读提质“最大增量”的关键一招。这段文字意在强调（）。若二维码无法识别，给公众号回复“2026国考合集”或“2026省考合集”即可。2020浙江A言语理解与表达",options:[{label:"A",text:"提供优质数字化阅读资源势在必行"},{label:"B",text:"数字阅读是青少年阅读的重要方式"},{label:"C",text:"数字阅读化时代更要重视文化传承"},{label:"D",text:"数字化技术是影响阅读的最大变量"}],answer:"A",explanation:"",tags:["逻辑填空","2024山东"],year:2024},{id:"v-fill-092",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"31.长期的城乡二元发展格局，导致城乡在科技、人才、资金及土地等要素配置方面严重不均衡，并且农村的优质资源还在源源不断地向城市集中，难以避免地造成农村产业萎缩乃至空心化。通过建立健全城乡融合发展机制，推动城乡要素自由平等交换，消除城市优质要素资源向农村流动的各种障得，才能真正形成乡村产业兴旺的基础条件。事实上，我国农村三产融合发展好的地方往往也是城乡融合发展程度高的地方。这段文字主要说明农村三产融合发展（）。",options:[{label:"A",text:"受制于城乡二元发展格局"},{label:"B",text:"需吸引城市优质要素资源的流入"},{label:"C",text:"与城乡融合的发展水平息息相关"},{label:"D",text:"应解决城乡间资源配置不均衡的问题"}],answer:"B",explanation:"",tags:["逻辑填空","2020浙江A"],year:2020},{id:"v-fill-093",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"32.从政策沿革来看，行业出现产能过剩时，治理政策通常先从拉动内需的角度去设计。实际上，_________________________。许多基础设施比较薄弱的新兴市场经济国家对传统产业产能需求还非常大，外部市场正在帮助解决内部需求不足的问题。",options:[{label:"A",text:"外部需求也是化解产能过剩的突破口"},{label:"B",text:"化解产能过剩还要更多依靠市场机制"},{label:"C",text:"化解产能过剩必然是个长期的过程"},{label:"D",text:"一味依赖市场扩容也仅仅是缓兵之计"}],answer:"B",explanation:"",tags:["逻辑填空","2020浙江A"],year:2020},{id:"v-fill-094",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"40.家长们担心孩子过度依赖手机会损害视力、看到不良信息。但值得注意的是，除了这些浅表层次的影响外，最重要的在于移动学习提高了学生的信息搜索能力，却也因答案的易得性而忽略了学生分析能力、创造能力的训练，这些才是学习最重要、最核心的部分。这段文字意在强调（）。若二维码无法识别，给公众号回复“2026国考合集”或“2026省考合集”即可。2021浙江A言语理解与表达",options:[{label:"A",text:"家长们为孩子过度依赖手机感到焦虑"},{label:"B",text:"过度依赖手机会对学生身体健康不利"},{label:"C",text:"移动学习提高了学生的信息搜索能力"},{label:"D",text:"移动学习对训练分析和创造能力不利"}],answer:"B",explanation:"",tags:["逻辑填空","2020浙江A"],year:2020},{id:"v-fill-095",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"34.如何定义垄断，尤其是如何界定互联网平台企业的垄断，存在不小的争议。垄断的危害人所皆知，可是也有人担心，如果反垄断的限制过大，可能会影响平台企业发展，不利于产生规模效应，从而影响市场繁荣。____________。如今，市场监管总局公布的标志性案例，证明“反垄断”已经切实成为悬在企业头上的达摩克利斯之剑，将会倒逼企业在做相关决策时，不得不三思而行。",options:[{label:"A",text:"传统的反垄断法律规则已与平台经济领域竞争呈现出的新特点不相适应"},{label:"B",text:"因此，推进互联网产业在全国层面、区域层面高度集中化发展是大势所趋"},{label:"C",text:"所以要正确处理好政府与市场的关系，简政放权、优化服务，激发市场活力"},{label:"D",text:"因为这种模糊性和争议性，许多互联网企业一直抱着侥幸心理，不断试探边界"}],answer:"D",explanation:"",tags:["逻辑填空","2021浙江A"],year:2021},{id:"v-fill-096",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"35.药品购销实施“两票制”，药品出厂一个价，进医院一个价，差价一目了然，可避免倒价。既然销量有保障，药企就没必要通过给回扣等方式来促销……一系列医改政策，已企的胃口，但由于销量和利润相关，药企仍难免会争取更大销量。尤其当多家药企的几手段可能会死灰复燃。",options:[{label:"A",text:"吃药品回扣的大漏洞虽已堵住，小漏洞仍会存在"},{label:"B",text:"可见，曾经猖獗的药品商业贿赂已得到明显遏制"},{label:"C",text:"不仅如此，医改政策还给许多药企带来了新利好"},{label:"D",text:"然而，一些无良医院和药企还是能钻制度的空子"}],answer:"D",explanation:"",tags:["逻辑填空","2021浙江A"],year:2021},{id:"v-fill-097",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"36.上世纪70年代以来，两栖动物正经历着全球性的种群下降和物种灭绝，下降速度之快、受胁物种之广，居各陆栖脊椎动物类群之首。但奇怪的是，很长时间以来，____________。因为很多两栖动物在远离人类干扰的偏远山区或自然保护区内突然消失，一些解释野生动物濒危的主流假说，如栖息地丧失、人类捕杀、气候变化等，都无法解释大量的两栖动物下降事件。因此，两栖动物的下降也曾一度被称作一场“神秘的下降”。",options:[{label:"A",text:"非野生的两栖动物种群并未出现明显下降"},{label:"B",text:"气候、环境等自然因素并没有发生剧烈变化"},{label:"C",text:"科学家找不到导致两栖动物种群快速下降的原因"},{label:"D",text:"全球两栖动物种群下降现象并未引起科学家的重视"}],answer:"C",explanation:"",tags:["逻辑填空","2021浙江A"],year:2021},{id:"v-fill-098",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"37.21世纪初，人口、经济和环境压力形成了独特的综合条件，使新出现和重现的传染病能以前所未有的规模传播。最近几十年的经验显示，_______________。而想要从根本上减少病毒国际传播可能性的最有效方法，就是世卫组织与其他组织、机构一起开展工作，加强全球疫情警报和反应网络，汇集世界各地的专家来一起应对疾病暴发。",options:[{label:"A",text:"烈性传染病发展为全球大流行的风险正在显著增强"},{label:"B",text:"应对疾病防控挑战的最有效手段就是采取预防措施"},{label:"C",text:"没有一个国家能够独自防范疾病及其它公共卫生威胁"},{label:"D",text:"建立一个实现各国数据共享的传染病数据库迫在眉睫"}],answer:"C",explanation:"",tags:["逻辑填空","2021浙江A"],year:2021},{id:"v-fill-099",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"31.并非所有的阅读都是一场对抗，一次______的对话。有谁未曾被一篇扣人心弦、______的论述所折服，未曾______在他人的思维里，而又被一声电话铃声或其他干扰拽回现实？",options:[{label:"A",text:"唇枪舌剑 字字珠玑 沉醉"},{label:"B",text:"雄辩高谈 丝丝入扣 迷醉"},{label:"C",text:"舌战群儒 笔底生花 沉浸"},{label:"D",text:"剑拔弩张 巧舌如簧 陶醉"}],answer:"B",explanation:"",tags:["逻辑填空","2023浙江A"],year:2023},{id:"v-fill-100",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"36.军事指挥员在未来战场上的谋优制胜能力取决于其军事思维发展水平，而要形成良好的军事思维能力，必须把战争制胜机理搞透。不同的战争形态，遵循不同的制胜机理，需要不同的思维方式。凡是罔顾军事实践发展、囿于陈旧观念的军队，必然会在战争中受到惩罚。事实证明，按照机械化条件下作战方式培养出来的指挥员，如果固守传统思维，是不能打赢信息化战争的。不清楚未来作战的制胜机理，就不能在实战化训练中及时增添反映未来作战的新要素、新内容、新手段，导调就只能在“老一套”上转圈圈，就无法引领参训官兵确立符合未来作战需要的思维。这段文字意在强调（）。",options:[{label:"A",text:"信息化战争对参战人员提出的新要求"},{label:"B",text:"提升指挥员军事思维发展水平的途径"},{label:"C",text:"培养方式对提升军事指挥员素质的影响"},{label:"D",text:"研究战争制胜机理对军事指挥员的意义"}],answer:"C",explanation:"",tags:["逻辑填空","2023浙江A"],year:2023},{id:"v-fill-101",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"37.研究发现，光的照射可对人体组织修复产生积极影响。据此，使用激光或发光二极管来提高人体组织修复能力，能够减少疼痛和炎症。利用这一光生物调节技术，研究人员开发出一种巴掌大小、既薄又轻、能均匀发出柔和治疗光的贴片。该贴片只需贴在伤口处，就能祛除伤痛，并通过不断刺激伤口愈合过程中起关键作用的真皮细胞增殖和迁移，帮助伤口愈合。研究人员表示，通过控制发射光的数量，还可扩大贴片的应用范围，治疗皮肤癌、阿尔茨海默症和抑郁症等病症。关于文中的“贴片”，下列说法不正确的是（）。",options:[{label:"A",text:"能够促进伤口愈合"},{label:"B",text:"可自动调节发射光的数量"},{label:"C",text:"可用于治疗阿尔茨海默症"},{label:"D",text:"利用了光可促进人体组织修复的原理"}],answer:"C",explanation:"",tags:["逻辑填空","2023浙江A"],year:2023},{id:"v-fill-102",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"38.在互联网社交化、移动化背景下，算法应用使广告的个性化、强互动和精准性特征变得非常突出，____________________。一方面，广告效果归因变得更加复杂。用户在多个社交平台中积极互动，消费者跨设备、跨媒体、线上线下行为交叉的情况也越来越多，如何精确测量单一平台的广告效果成为现实问题。另一方面，目前互联网广告常用的方法都无法追踪用户在其他渠道中的转化。以视频信息流广告为代表的一类广告存在着极强的推荐、分享等性质，用户与之相关的消费行为可能是在其他渠道中完成的。",options:[{label:"A",text:"广告效果转化呈现跨界的特性"},{label:"B",text:"传统的广告测量方法面临挑战"},{label:"C",text:"广告从投放到获得收益存在诸多环节"},{label:"D",text:"算法应用在广告效果归因上具有局限性"}],answer:"D",explanation:"",tags:["逻辑填空","2023浙江A"],year:2023},{id:"v-fill-103",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"43.在我国的传统花卉中，紫薇花算得上是名花之一。紫薇树姿优美，花色艳丽，花期可长达数月，素有“百日红”之美誉。南宋《全芳备祖》的作者陈景沂，甚至将紫薇花赞为“花之圣”。按常理来说，这种艳丽如霞的奇葩，应深受历代文人墨客的青睐。但奇怪的是，古人虽留下许多歌咏紫薇的佳作，却在“绘事”方面甚少留下墨迹。这段文字接下来最可能说的是（）。",options:[{label:"A",text:"紫薇花这个美丽名称的由来"},{label:"B",text:"紫薇花为何被称为“花之圣”"},{label:"C",text:"历代诗人歌咏紫薇花的名篇"},{label:"D",text:"古代画家为何很少画紫薇花"}],answer:"D",explanation:"",tags:["逻辑填空","2023浙江A"],year:2023},{id:"v-fill-104",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"44.在电商业、快递业高速发展的背景下，多家企业纷纷进军无人机物流领域，将其视为降低成本、提高效率之举。无人机送快递看上去有很多优势，比如可到达传统物流难以到达的偏远地区，可让快递在交通拥堵的城市快起来等。但从现实情况看，无人机送快递不会那么快实现。目前拿到“证”的企业，只能在批准的空域内试点飞行，而且无人机不直接面对普通用户，只是将物品送到某个配送点。此外，限制无人机物流广泛应用的另一个原因是安全问题，这既指无人机自身安全，也是指快件安全，更是指公众人身及财产安全。这段文字主要介绍（）。",options:[{label:"A",text:"当前无人机配送难以普及的原因"},{label:"B",text:"企业重视发展无人机物流的动机"},{label:"C",text:"安全问题对无人机物流的重要意义"},{label:"D",text:"无人机配送在现代物流领域的地位"}],answer:"A",explanation:"",tags:["逻辑填空","2023浙江A"],year:2023},{id:"v-fill-105",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"45._______________。新中国成立以来，很多画家借用西方的一些画法创作山水画，大多不太成功，也很难得到国人的认可。在这方面较为成功的是李可染和赖少其。他们都有深厚的传统文化功底，年轻时向传统大家学习，精研书法，长期写生。在打牢传统的各种基础后，李可染将光引入艺术表现，尤善用积墨画逆光；赖少其学习西方印象派等画法，借鉴西洋画的着色方式，和传统融合得很好。所以，他们笔下的祖国河山仍然体现出雄浑厚重、大气磅礴的中国精神。",options:[{label:"A",text:"中西融合是二十世纪中国画面对的世纪课题"},{label:"B",text:"中国画具有独特的文化特质和内在发展逻辑"},{label:"C",text:"中国画家借鉴外来艺术时需有良好的传统功底"},{label:"D",text:"借鉴西洋画艺术手法取得成功的中国画家很少"}],answer:"C",explanation:"",tags:["逻辑填空","2023浙江A"],year:2023},{id:"v-fill-106",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"50.用不了几十年，人工智能就会超越多种人类自认独有的能力。对我们这一代人来说，这是个巨大的挑战，也许我们需要“非理性”地应对。计算机占领了曾专属于人类的工作——那些需要知识、策略甚至创造力的工作。在这种“劳动分工”之下，我们应把人类的工作定位在与机器互补，而非与之相抗衡上。重视机器带来的挑战，意味着我们需要作出改变，刻不容缓。同时，相信创造力是人类特有的价值，即使机器超越人类，我们仍拥有地球上最具创造力的脑袋，里面装着天马行空的想法和深沉复杂的情感。下列哪一说法与作者的观点不相符？（）若二维码无法识别，给公众号回复“2026国考合集”或“2026省考合集”即可。2024浙江A言语理解与表达",options:[{label:"A",text:"人类应该及时应对人工智能带来的挑战"},{label:"B",text:"人类的创造力不会被人工智能完全取代"},{label:"C",text:"人类的知识是与人工智能相抗衡的基础"},{label:"D",text:"人类与人工智能可在不同领域实现互补"}],answer:"A",explanation:"",tags:["逻辑填空","2023浙江A"],year:2023},{id:"v-fill-107",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"30.科技合作是构建更加开放、包容、普惠、平衡、共赢的经济全球化的______。全球化和开放型经济是过去几十年人类进步的两个关键因素。当世界正朝着以知识为基础的经济跃进，对中国采取科技______打压正在损害知识的产生和创新，与增进人类科技进步与共同福祉______。",options:[{label:"A",text:"成功之道 封锁 适得其反"},{label:"B",text:"必然之果 束缚 殊途同归"},{label:"C",text:"应有之义 遏制 背道而驰"},{label:"D",text:"必由之路 围猎 南辕北辙"}],answer:"C",explanation:"",tags:["逻辑填空","2024浙江A"],year:2024},{id:"v-fill-108",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"31.先秦儒学传世文献与出土文献中，存在着大量的引诗叙事。这些引诗叙事或因其义理方式不够“纯粹”，或因其文献形态不够“经典”，往往被______，甚至被忽视乃至遗忘其思想价值。然而这些引诗叙事，并不是先秦儒学诸子______的。研究先秦儒学的引诗叙事，是还原先秦儒学的原始生命、______先秦儒学的诗性智慧、彰显先秦儒学的中国哲学特质的重要路径。",options:[{label:"A",text:"轻描淡写 率性而为 突出"},{label:"B",text:"一带而过 随意而为 昭示"},{label:"C",text:"弃如敝履 随心所欲 揭示"},{label:"D",text:"熟视无睹 随其所宜 凸显"}],answer:"B",explanation:"",tags:["逻辑填空","2024浙江A"],year:2024},{id:"v-fill-109",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"33.就文化优势而言，除了文本、唱腔、演艺、舞台之美等自不待言之外，杂剧还有一个别的古典文学品种______的特点，就是入世性，以及由此而来的普及性和强大影响力。几百年来，______的杂剧，潜移默化地______着民众的是非荣辱观。",options:[{label:"A",text:"望其项背 脍炙人口 支配"},{label:"B",text:"望尘莫及 源远流长 孕育"},{label:"C",text:"无出其右 博采众长 建构"},{label:"D",text:"无可比拟 寓教于乐 塑造"}],answer:"D",explanation:"",tags:["逻辑填空","2024浙江A"],year:2024},{id:"v-fill-110",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"39.根据这几段文字，下列说法一定不正确的是（）。",options:[{label:"A",text:"有大气和磁场就会出现极光"},{label:"B",text:"极光是一种强烈的电磁干扰源"},{label:"C",text:"水星上没有大气，不可能出现极光"},{label:"D",text:"极光是一种绚丽多彩的等离子体现象"}],answer:"A",explanation:"",tags:["逻辑填空","2024浙江A"],year:2024},{id:"v-fill-111",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"42.现下的非遗资源正被作为一种审美意识驱使下的文化资本推向市场。传统技艺、美术等具有固定表现形式和物质载体的非遗项目，被开发为可复制形式、可批量生产的有形商品流通、销售。而民间文学、表演艺术、民俗等没有特定物质载体的非遗项目，产出的则是以视觉、听觉、触觉等感官体验为主导的无形产品，它们被采用全媒体、数字化的生产模式向公众传播并获得盈利。________________，却拥有商品的属性和价值。",options:[{label:"A",text:"非物质文化商品丧失了可复制性"},{label:"B",text:"这些非遗产品固然没有实体样态"},{label:"C",text:"这些非遗项目尽管市场拓展度低"},{label:"D",text:"文化产品虽需要特定的物质载体"}],answer:"B",explanation:"",tags:["逻辑填空","2024浙江A"],year:2024},{id:"v-fill-112",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"44.过去二十多年来，有关中国文明起源的考古发现迎来了前所未有的高潮，良渚、陶寺、石峁、石家河等古城及相关考古遗存的揭示，充分展现了早期中国文明丰富多样的发展模式。考古发现与研究显示，早期中国文明是一个存在密切联系的互动圈，是一个相对独立且完整的体系，但并不封闭。不过，“中原中心论”并没有完全消失，它的升级版就是“华夏—边缘论”，即认为农耕区的中国文明才是华夏中心，其余是边缘。这种考察视角有失偏颇，与真实历史不符，我们应该从更大范围的互动中来考察中国文明的形成过程。这是一篇文章的引言部分，这篇文章主要讨论的是（）。",options:[{label:"A",text:"早期中国文明的互动和演进模式"},{label:"B",text:"“中原中心论”观点的来源和缺陷"},{label:"C",text:"考古对追溯中国文明起源的重要价值"},{label:"D",text:"地理环境对中国文明演进的重要影响"}],answer:"A",explanation:"",tags:["逻辑填空","2024浙江A"],year:2024},{id:"v-fill-113",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"45.智能计算机技术成为开启数字文化产业未来畅想的金钥匙。如果说传统文化产业发展的原动力源于文化消费的市场化，那么在数字化转型期，市场的无形之手已变成数字化之手，文化产业消费市场越来越多地由头部数字平台承接并管理，_____________，同样的逻辑亦能解释文化产业的持续数字化对于前沿技术的强劲需求。虚拟现实、增强现实、人工智能、区块链以及不断创新的各类应用软件技术，正全面应用于文化产业大发展中，通过“技术+文化”赋能文化产业创新，改变文化产业面貌。",options:[{label:"A",text:"选择优质的数字技术平台成为企业发展关键"},{label:"B",text:"坚持技术创新才能促进文化产业高质量发展"},{label:"C",text:"智能数字技术成为发展文化产业新一轮动力"},{label:"D",text:"要同时有效发挥有形之手和无形之手的作用"}],answer:"C",explanation:"",tags:["逻辑填空","2024浙江A"],year:2024},{id:"v-fill-114",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"43.市场化的志愿填报指导，说白了是利用“信息差”赚钱。学校、教育部门等联合“出手”，充分发挥各自优势，为考生提供专业、系统、免费的志愿填报指导，不啻为一场志愿填报服务的“供给侧改革”。“阳光志愿”这一权威选择，有利于帮助考生和家长“避坑”，缓解选择焦虑。高考志愿填报指导服务普惠化，也更契合高考公平的内在要求。毕竟，不是每个家庭都有条件去购买高价志愿填报指导服务。同时，更科学、靠谱的“官方”版志愿填报指导服务上线，也能倒逼相应的市场化服务规范发展，产生良币驱逐劣币的正向作用。根据这段文字，“阳光志愿”可能是（）。",options:[{label:"A",text:"高校招生信息服务平台"},{label:"B",text:"志愿填报指导服务系统"},{label:"C",text:"高考志愿填报咨询公司"},{label:"D",text:"高校毕业生就业指导机构"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-115",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"44.体育文化是我国传统文化的重要组成部分，随着科技革命的不断深入，体育文化传承发展迎来了新的机遇。数字科技能够提供新的体育文化传播发展平台，将先进的数字设备应用到体育赛事活动中，通过云数据平台进行赛事活动宣传，丰富赛事的文化内涵。数字体育还可通过技术创新、不断推出数字化的体育文化产品，进一步达到普及体育运动的目的。最适合做这段文字标题的是（）。",options:[{label:"A",text:"数字技术：促进体育文化繁荣的新媒介"},{label:"B",text:"数字体育：体育产业高质量发展新动能"},{label:"C",text:"体育文化：普及全民体育运动的新抓手"},{label:"D",text:"体育传播：数字技术带来发展的新机遇"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-116",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"45.__________________。这是诗歌鉴赏和审美体验对诗歌创作提出的要求。钱钟书在《谈艺录》中说：“夫言情写景，贵有余不尽。然所谓有余不尽，如万绿丛中之着点红，作者举一隅而读者以三隅反，见点红而知嫣红姹紫正无限在。”诗作里的一点“红”，透露了春天的气息；读者在鉴赏中举一反三，自然会在脑海中浮现出万紫千红的春色。",options:[{label:"A",text:"诗以简约含蓄为贵"},{label:"B",text:"诗以言辞优美为贵"},{label:"C",text:"诗以情感真挚为贵"},{label:"D",text:"诗以浑然天成为贵"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-117",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"27.一个国家的发展应该致力于将经济发展的蛋糕做大，在此基础上，注重公平的分配。对区域经济发展来说，应牢牢建立比较优势的概念。不同地方在自然地理条件上有巨大的差异。即便是两个自然条件完全相同，地理上相邻的省份或城市，最佳发展模式也不是大家发展同样的生产结构，而是应该各自有分工。作者通过这段文字重在强调（）。",options:[{label:"A",text:"不同地理条件的区域发展模式应当有所不同"},{label:"B",text:"地理相邻的两个城市也应该有各自不同特色"},{label:"C",text:"不同区域经济发展应与当地比较优势相吻合"},{label:"D",text:"最佳发展模式并不适合所有地理条件的区域"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-118",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"28.群体免疫力是一种保护整个社区免受疾病侵害的手段：通过免疫社区里足够多的人，有效地打断疾病从一个人传染到另一个人的接力，中断感染链，从而保护少数不能接种疫苗的人群。但是，这个模式要真正起作用，社区中接种疫苗的人必须足够多。接种疫苗的人数必须高于一个最小的百分值（学术界称之为“阈值”），群体免疫才会生效。接种的社区成员越多，_____________________。",options:[{label:"A",text:"整个社区就越能够避免疾病的爆发"},{label:"B",text:"才能有效阻断疾病源感染整个社区"},{label:"C",text:"越能保护少数拒绝接种疫苗的人群"},{label:"D",text:"整个社区的免疫模式才能发生作用"}],answer:"C",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-119",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"30.在电影表现的技术层面，数字技术事实上已经代替了同源成像技术，出现了由电脑生产影像所构造的故事片。电脑生产的影像已经不再局限于单纯的特技效果，他们构成了影片全部蒙太奇中的镜头，主要角色都是完全或部分由电脑合成。在电影的发行和放映环节，具有质感的胶片卷，放映机吵闹的声音，抑或是影像剪辑表，还有流动于影院之间装胶片的金属盒，正在一个个地消失于我们的视线，成为历史。下列对文意概括最恰当的是（）。",options:[{label:"A",text:"数字技术已经颠覆了以往电影生产发行全过程"},{label:"B",text:"当前电影艺术表现完全离不开数字技术的辅助"},{label:"C",text:"数字合成技术取代了电影制作中各种拍摄手法"},{label:"D",text:"同源成像技术在电影拍摄技术层面已成为历史"}],answer:"B",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-120",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"39.执法检查是人大行使宪法法律赋予的监督权，也是保证法律得到全面有效实施的一把“利剑”。既然是“利剑”，就必须锋利，而不是______、无关痛痒。有力度、有硬度的执法检查，才能______法律的权威。为什么有的执法检查所呈现的结果却与老百姓的切身感受______？其中原因恐怕还在于执法检查没到位。",options:[{label:"A",text:"蜻蜓点水 彰显 大相径庭"},{label:"B",text:"畏首畏尾 体现 千差万别"},{label:"C",text:"畏葸不前 突显 南辕北辙"},{label:"D",text:"声东击西 宣告 失之千里"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-121",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"40.中国彩陶很注意图案纹样与器型的关系，______而统一谐调，也注意彩陶图案在不同______所产生的不同效果。这种以彩绘纹样与造型______完美结合的艺术手法，同时也成为传统雕塑和工艺美术极有特色的表现手法。",options:[{label:"A",text:"交相辉映 角度 天衣无缝"},{label:"B",text:"五彩缤纷 位置 错落有致"},{label:"C",text:"千变万化 方向 有目共睹"},{label:"D",text:"相辅相成 视角 浑然一体"}],answer:"C",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-122",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"42.下列对膳食纤维的描述不符合文意的是（）。",options:[{label:"A",text:"可以是感觉上非常软嫩细滑的食物"},{label:"B",text:"不可能被肠胃中的消化酶完全消化"},{label:"C",text:"两类膳食纤维对人体作用不尽相同"},{label:"D",text:"每天食用含膳食纤维食物多多益善"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-123",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"20.专家认为，近视一旦发生，不可逆转。特别是在低年龄阶段发生近视的孩子，更容易变成高度近视，导致视力损伤。充分接触阳光可以有效地保护视力。每天2小时、每周10小时以上的户外活动，可使青少年的近视发生率降低10%以上。这主要因为太阳的光照强度比室内光照强度高数百倍，光照越强，多巴胺释放量越多，而多巴胺能抑制近视的发生发展。高强度光照一方面可使瞳孔缩小、景深加深、模糊减少，另一方面也能起到抑制近视的作用。这段文字重在说明（）。",options:[{label:"A",text:"低龄近视是光照弱引发的视力损伤"},{label:"B",text:"太阳光照能有效抑制近视发生发展"},{label:"C",text:"光照强度与近视发生率呈现负相关"},{label:"D",text:"户外活动可以有效预防近视的发生"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-124",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"21.所谓历史，通俗地讲就是已经发生过的事实。如果从时间尺度来讲，历史是增加了时间尺度标记的现实。而所谓现实，就是正在发生的事实，因此，也可以说从时间尺度讲是标度为零的事实。实际上，如果从时间轴来看，作为时间零标度的现实一直是在持续变动的。这种变动使得时间尺度轴上的绝大多数事实，都飞快地成为历史，只是其所具有的时间刻度是不同的。作者通过这段文字重在说明（）。",options:[{label:"A",text:"已经发生过的事件均可载入历史"},{label:"B",text:"每时每刻都在发生新的历史史实"},{label:"C",text:"不同时段的历史仅是记载的时间刻度不同"},{label:"D",text:"历史与现实的区分主要依据已然或者未然"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-125",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"22.经济法法治理论的构建，需要关注法治理论的一般问题，包括法治理念、法治价值、法治目标、法治手段、法治运行、法治实效等，并应当探讨法的稳定性与变易性、确定性与模糊性等问题。在此基础上，应结合经济法的特殊性和经济法治的特殊问题，深化经济法的立法理论特别是法律优化理论的研究，以促进经济法从“法”到“良法”的发展，__________________。",options:[{label:"A",text:"从而提升立法质量和法治水平"},{label:"B",text:"提升经济法基本理论研究水平"},{label:"C",text:"提高经济法的法治理论水平"},{label:"D",text:"进而构建高水平经济法理论"}],answer:"B",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-126",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"37.农产品销路问题，事关国计民生、产业转型，影响着农村发展后劲。不过，打开销路，______还是要看农产品的品质。为此，在______的销售市场中，应当积极引导农户转变经营观念、革新种植技术，培育更多优质农产品，努力在扩大销路与提升品质之间形成______。",options:[{label:"A",text:"追根溯源 硝烟四起 互利共赢"},{label:"B",text:"归根结底 优胜劣汰 良性循环"},{label:"C",text:"说千道万 品质为王 动态平衡"},{label:"D",text:"千头万绪 不进则退 联动机制"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-127",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"40.科研人员是科技创新的核心力量，也是科普创作和科学传播的重要生力军。然而，由某科普研究所开展的一项调查显示，相比之下，我国的科普人力资源严重失衡，尤其是作为科普源头的科普创作人力资源更是______。推动科研人员参与科普事业，成为______。国家也在倡导科研人员参与科普，从科研人员的角度来说，这也是______的事情。",options:[{label:"A",text:"难以为继 燃眉之急 义不容辞"},{label:"B",text:"凤毛麟角 重中之重 理所当然"},{label:"C",text:"后继无人 人心所向 舍我其谁"},{label:"D",text:"捉襟见肘 当务之急 责无旁贷"}],answer:"C",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-128",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"26.獬豸，是中国古代神话传说中的“法兽”，据《论衡》中描述，其双目明亮有神，独角，能辨是非曲直，能识善恶忠奸，有勇猛、公正的寓意。在我国一些法院门口，往往能看到獬豸的雕像，象征着对公平正义的守护。公平正义是司法的灵魂，是人民群众感知法治建设的一把尺子。推进全面依法治国，要紧紧围绕保障和促进社会公平正义来进行，把这一价值追求贯穿到立法、执法、司法、守法的全过程和各方面。这段文字意在强调（）。",options:[{label:"A",text:"古代典籍描述的獬豸是法治的象征"},{label:"B",text:"司法公平是社会的底线公平"},{label:"C",text:"法治建设要贯穿于法制工作的全过程"},{label:"D",text:"公平和正义，是法治的生命线"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-129",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"27.互联网新闻业颠覆了新闻媒介和职业记者是公众与消息来源和信息准确可靠性之间权威通道的传统理念。以往优秀的职业记者和强大公信力的媒介机构在获取消息来源、验证信息准确度方面具有得天独厚的资源和优势，这也是职业与非职业新闻业之间的分野所在。然而今天，除了各类消息来源都可以直接面对公众之外，遍布全球、专业高效的互联网用户，也使得信息的交叉验证变得比以往更为便捷。简而言之，媒介机构不再是新闻事件的权威阐释主体，新闻报道的价值和意义______________。",options:[{label:"A",text:"已然掌握在互联网各类新媒体手中"},{label:"B",text:"不再由传统的权威新闻媒体所定义"},{label:"C",text:"由互联网用户的广泛参与而消解"},{label:"D",text:"经由公众的集体参与而被重塑"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-130",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"37.植物科学画和摄影是完全不同的门类。我们有时候称赞照片，说它美得像幅画，但其实绘画和摄影在艺术上______。哪怕再好的画师，也无法像摄影那样全面______那一瞬间的景象；而有时候，摄影又无法像植物科学画那样表达出一颗绿绒嵩盛开时那种对生命和繁衍的渴望。摄影当然可以呈现某一物种的全貌，但是乍一看，特征不会那么明显，植物科学画则可以着重呈现物种特征，更加______。",options:[{label:"A",text:"相辅相成 捕获 纤毫毕现"},{label:"B",text:"各擅胜场 凝固 栩栩如生"},{label:"C",text:"大相径庭 定格 有的放矢"},{label:"D",text:"各有千秋 还原 一目了然"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-131",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"38.新一轮科技和产业革命风起云涌，席卷全球。各大科技强国的中心城市______，力图摘取全球“科创策源地”这一______，这是一个能够激起世界级城市管理者内心澎湃的宏伟目标。作为策源地，不仅意味着科学上的领先，还意味着最先进的高科技产业和最具创新能力的企业家的集聚，能够在城市中水乳交融，______，向外源源不断地释放出能量。",options:[{label:"A",text:"争先恐后 盛誉 交相辉映"},{label:"B",text:"各显神通 美称 互通有无"},{label:"C",text:"各尽所能 桂冠 相得益彰"},{label:"D",text:"尽心尽力 殊荣 取长补短"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-132",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"39.当下发展迅速的社会生活带来了多种多样的语言新现象。词语是时代变迁的监测器，新事物______，新现象日新月异，词库便随之不断______。从融媒体到神经网络、区块链、多重体验、数据信托，各类新词新语______。",options:[{label:"A",text:"应接不暇 推陈出新 不可胜数"},{label:"B",text:"屡见不鲜 弃旧图新 俯拾即是"},{label:"C",text:"接踵而至 去芜存菁 恒河沙数"},{label:"D",text:"层出不穷 吐故纳新 不胜枚举"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-133",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"40.在人文领域，人文学者担负的任务首先而且主要是“传承”人类文化，是理解、解释从而传播人文经典。评价一个人文学者学术水平的基本标准是，他熟悉多少经典著作，能在多大程度上______经典著作，本着当代人面临的问题开展与伟大经典的对话。至于创造性思想，那是一种______的事情，有些才能杰出者或许可以提出富有创造性的思想，甚至提出自己独特的理论体系，但那是人文学者“修炼”过程中______的事情，不应该是预先设立的目标。",options:[{label:"A",text:"阐释 可遇不可求 水到渠成"},{label:"B",text:"精通 难能可贵"},{label:"C",text:"诠释 可望不可即 自然而然"},{label:"D",text:"通晓 不可多得"}],answer:"C",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-134",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"20.通过“线下生产+线上数据分析”模式，传统产业能够在规模化生产之外，探索开展个性化定制服务。比如，先生产小批量产品投放市场，再通过数据分析细分需求决定是否扩大生产。这种“轻资产、快反应”的柔性供应链模式，增加了产品研发、制造和流通的弹性，能帮助解决传统供应链模式下机会成本高、运转周期长等问题。这样的生产变革，能够通过精细化运营实现供需精准匹配，是一种更加适合中小企业数字化转型的模式，能让中小企业以“小单快返”的新模式轻装上阵，形成独特的竞争优势。这段文字意在说明（）。",options:[{label:"A",text:"传统产业需借助数据分析突破固有局限"},{label:"B",text:"数字赋能可助力中小企业提升竞争优势"},{label:"C",text:"供需的动态平衡是中小企业发展的关键"},{label:"D",text:"企业的数字化转型重在构建柔性供应链"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-135",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"21.与射电望远镜相比，大型光学望远镜对环境的要求更加苛刻，比如晴夜数、天光背景亮度、视宁度等，所以优质的光学观测台址是稀缺资源。此前国际优质的大型光学望远镜几乎都集中在西半球。而我国青海省冷湖台址区域每年可观测时间达300天，可沉降水汽柱也远优于其他地区的大型光学天文台。冷湖所在的经度区域尚属世界大型光学望远镜的空白区，由于天文观测常需要接力观测，随着冷湖天文观测基地的建设，这里将成为国际光学天文研究的重要基地。下列说法与文意不符的是（）。",options:[{label:"A",text:"东半球优质光学观测设施相对稀缺"},{label:"B",text:"大型光学天文台建设选址难度大"},{label:"C",text:"大型光学望远镜对环境要求高，故观测精度高于射电望远镜"},{label:"D",text:"冷湖地区得天独厚的环境将使其成为天文科学研究重镇"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-136",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"22.博物馆研学，要“研之有物”“学而广博”。博物馆研学不是“打卡”拍照的旅游，也不仅是提供托管服务，而是要让年轻一代明白，生而为中国人，最根本的是有中国人独特的精神世界，有百姓日用而不觉的价值观。近年来，中华文明探源工程等重大工程的研究成果，进一步证实了我国悠久的人类史和璀璨的文化史，其中也包含着中华优秀传统文化、革命文化和社会主义先进文化。这些都被缩影于文物当中。因此，博物馆研学，就是要___________________。",options:[{label:"A",text:"从文物中学习这些文化"},{label:"B",text:"深入了解中华文明的独特性"},{label:"C",text:"不断提高自身文化素养"},{label:"D",text:"有的放矢地学习历史和文化"}],answer:"B",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-137",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"40.“地铁会合点”的选择虽然并非大手笔，但蕴含着城市善治的大道理。城市让生活更美好，这不仅体现在高楼大厦、车水马龙的繁华图景里，也蕴含在日常生活的______中。满足老百姓更高品质的生活需求，不仅需要用科技手段实现______，也需要用“绣花功夫”提升公共场域管理服务的精细化、______水平。",options:[{label:"A",text:"细枝末节 智能化 人性化"},{label:"B",text:"日积月累"},{label:"C",text:"熙熙攘攘"},{label:"D",text:"井然有序"}],answer:"C",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-138",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"29.数字货币利用大数据与区块链技术，能够高效记录并存储交易信息及货币流向。这种技术的应用使得货币的创造、流通和监控过程变得更加透明和高效。具体来说，大数据技术的运用使得货币政策的制定者可以快速获取大量实时的经济活动数据，极大提高了数据的准确性和政策制定的针对性。区块链技术的特性——分布式账本，为货币流通提供了一个安全可靠的环境，确保了交易信息的不可篡改和实时追踪，降低了监控成本并减少了实施滞后。此类技术革新为中央银行在制定和实施货币政策时提供了强大的数据支撑，使政策更加精准地匹配经济情况的实际需求。这段文字重在说明（）。",options:[{label:"A",text:"数字货币使货币政策的制定实施更精准和高效"},{label:"B",text:"数字货币在金融监管方面具有较大的应用价值"},{label:"C",text:"大数据与区块链技术有利于推动宏观经济发展"},{label:"D",text:"大数据与区块链技术为货币流通提供安全保障"}],answer:"C",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-139",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"30.从古村落整体发展的层面来看，其更新改造过程中应。如今的古村落物质空间形态是不同历史发展阶段不断叠加的产物，其中既有人们在村落整体空间布局结构、街巷空间肌理等方面的精心谋划，体现了人与自然和谐共生、文化追求等方面的精髓，也有人们在不同年代由于认识不足或其他原因导致的种种改变。因此，要深入研究古村落历史发展沿革，提取古村落选址和布局中的山水田园人居精华，做到去芜存菁，通过更新改造，更好体现古村落在整体空间布局方面的生态智慧和人文内涵，凸显古村落的整体风貌特色和历史文化价值。",options:[{label:"A",text:"辩证处理“取”与“舍”的关系"},{label:"B",text:"将文化遗产保护与文旅资源开发相结合"},{label:"C",text:"正确对待历史文化价值同特色产业发展的关系"},{label:"D",text:"把挖掘历史文化内涵同打造特色文化品牌统一起来"}],answer:"B",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-140",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"40.中华法系形成于秦朝，至隋唐日趋成熟，宋元明清时期______形成了影响深远的成文法典，在历史发展中______而成的中华法系彰显了中华优秀传统法律文化自我发展、回应挑战的主体性与生命力，也反映了中华文明______的延续性。",options:[{label:"A",text:"陆续 积淀 源远流长"},{label:"B",text:"相继 淬炼 一脉相承"},{label:"C",text:"渐次 聚集 薪火相传"},{label:"D",text:"稳步 嬗变 生生不息"}],answer:"C",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-141",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"41.在新中国科技史和工业史上，中国核事业的奠基之作、______的“一堆一器”，作为我国建设的第一项原子能设施，彰显了新中国的硬实力。从基础研究，到“两弹一艇”研制，再到和平利用原子能，“一堆一器”______。虽然，通过报刊书本、影视荧屏，我们对“一堆一器”并不完全陌生。然而，当它们“活生生”地出现在眼前时，惊喜与感动依旧______，关于它们的故事与传奇、过往与现状，依然牵动人心。",options:[{label:"A",text:"闻名遐迩 举足轻重 情不自胜"},{label:"B",text:"声名显赫 劳苦功高 不期而至"},{label:"C",text:"大名鼎鼎 功不可没 油然而生"},{label:"D",text:"举世无双 功勋卓著 汹涌澎湃"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-142",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"42.对于人类而言，“逝去之物”总具有独特的魅力。人们难以遏制对“起源”的遐想，并做出______般的追问。考古发掘让早已湮灭的文明再见天日，通过窥探遗迹的里里外外、角角落落，用发现的物证来______历史的图景。文物既旧也新，它不仅可以证实或证伪我们关于历史的记忆和想象，更重要的是复活了被遗忘的文明的璀璨艺术，让那些______的美再次绽放。",options:[{label:"A",text:"剥茧抽丝 再现 深藏不露"},{label:"B",text:"愚公移山 组合 巧夺天工"},{label:"C",text:"精卫填海 拼合 不为人知"},{label:"D",text:"夸父逐日 还原 不可替代"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-143",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"43.中国探月20年，拉近了______与普通公众生活的距离。当一粒棉花种子在月球上生根发芽，当月球车玉兔微博下满是网友的祝福，当中小学教材换上了崭新的中国月面图……越来越多的人与探月工程的某项成果、某个侧面______，一个共识在人们心中不断______：我们离月球并不遥远！",options:[{label:"A",text:"碧海青天 邂逅相逢 汇集"},{label:"B",text:"浩瀚苍穹 心心相印 回响"},{label:"C",text:"星辰大海 不期而遇 凝聚"},{label:"D",text:"蟾宫折桂 情投意合 激荡"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-144",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"44.自上古时期以来，华夏先民就通过粟和黍的栽培、陶器的烧制、冶铁的发明，______了农业文明的辉煌篇章；汉唐之际，从造纸术到雕版印刷，这些发明创造为文化传承发展提供了重要______；宋元以降，《梦溪笔谈》《授时历》《天工开物》《本草纲目》等科学典籍的问世，无一不是中华民族______、与时俱进的优秀典范。",options:[{label:"A",text:"谱写 借鉴 除旧布新"},{label:"B",text:"铸就 载体 蜕故孳新"},{label:"C",text:"绘制 支撑 吐故纳新"},{label:"D",text:"开启 依托 革故鼎新"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-145",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"45.巍巍华山阻住了奔腾南来的黄河，逼其90度大拐弯。原来被高原土层______着的黄河，一旦向东越过三门峡进入华北平原，顿时就变成了在平地上______的“野马”，成了到处滚动、狂奔的地上河，一会儿从东北方向流入渤海，一会儿又从东南方向夺取淮河河道注入黄海。万年千年间，黄河携带的泥沙渐渐______出了美丽富饶的华北平原。",options:[{label:"A",text:"环抱 狂放不羁 凝固"},{label:"B",text:"挟持 肆无忌惮 淤积"},{label:"C",text:"裹挟 自由驰骋 沉淀"},{label:"D",text:"束缚 风驰电掣 积累"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-146",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"50.下列最适合做这篇文章标题的是（）。若二维码无法识别，给公众号回复“2026国考合集”或“2026省考合集”即可。2018国考言语理解与表达（地市级+副省级）",options:[{label:"A",text:"作物种质库里的未来农业"},{label:"B",text:"平凡的种子，不平凡的“家”"},{label:"C",text:"国家作物种质库：生命的起点"},{label:"D",text:"“种子诺亚方舟”守护农业火种"}],answer:"B",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-147",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"35.进行骨髓移植的前提条件是有配型成功的捐赠者。双胞胎配型成功几率最高，兄弟姐妹也有可能。但在中国，20世纪70年代到现在，大多数都是独生子女，有兄弟姐妹且能配型成功的概率也非常低。另外，父母和子女之间骨髓配型成功的概率非常低，几乎为零。因此，绝大多数患者都必须依赖不认识的志愿者配型。非亲缘关系骨髓配型成功的几率只有几十万至几百万分之一，__________________________。",options:[{label:"A",text:"即使这样，骨髓移植仍是大多数血液疾病患者的唯一希望"},{label:"B",text:"如果冒着风险使用不完美的配型，成功率自然会大为降低"},{label:"C",text:"骨髓库里志愿者样本的多少，直接决定着病人找到合适配型的几率"},{label:"D",text:"志愿者捐献固然很重要，国家相关政策的落实和执行也是当务之急"}],answer:"C",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-148",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"39.当我们仔细观察当今世界上的主流火箭时，就会发现它们用的发动机、燃料箱等都是上世纪的产物。比如要在2018年首飞的太空发射系统用的是改进过的航天飞机的火箭发动机，燃料箱用的是改进过的航天飞机的外挂燃料箱，两侧的固体燃料推进器用的也是改进过的航天飞机的固体燃料推进器。__________________。火箭是非常复杂的东西，设计并制造火箭需要考虑的因素太多，就连火箭制造商们也只能去选择一些经受过时间考验的产物，从而确保产品的可靠性。",options:[{label:"A",text:"这是因为新技术的推广需要一定的时间"},{label:"B",text:"这并不意味着火箭技术没有任何新的进展"},{label:"C",text:"事实上，制造火箭的材料并不都是前沿科技产物"},{label:"D",text:"也就是说，在火箭这个领域内并不是最新的就是好的"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-149",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"46.关于康博伊研究小组的实验，下列说法正确的是（）。",options:[{label:"A",text:"两只小鼠通过外科手术完成了换血实验"},{label:"B",text:"新旧血液交换后需要 5 天才能充分混合"},{label:"C",text:"老年小鼠的肝脏组织发生了年轻化改变"},{label:"D",text:"换血实验对于年轻小鼠来说有更大影响"}],answer:"D",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025},{id:"v-fill-150",module:l.VERBAL,subCategory:e.LOGICAL_FILL,difficulty:t.MEDIUM,stem:"49.下列哪项不是对康博伊研究小组的实验提出的质疑？（）",options:[{label:"A",text:"没有明确指出抑制因子的物质成分"},{label:"B",text:"两只体重 30 克的小鼠交换了 150 微升血液"},{label:"C",text:"在两只小鼠换血 5 天后得出了观察结果"},{label:"D",text:"两只小鼠分别相当于人的 20 岁和 80 岁"}],answer:"A",explanation:"",tags:["逻辑填空","2025浙江A"],year:2025}];export{a as verbalFillBlankQuestionsPart1};
